import { NextResponse } from "next/server";
import { auth } from "@/auth";

export async function POST(req: Request) {
    try {
        const session = await auth();
        if (!session?.user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        // Cloudflare Pages requires a more complex setup (Account ID + API Token)
        // and usually requires creating a project first before uploading files.
        // For this implementation, we will return a descriptive error telling the user
        // to use Vercel or Netlify for instant deploys, or we can implement the full
        // Cloudflare Direct Upload API if the user provides both IDs.

        return NextResponse.json(
            { error: "Cloudflare Pages deployment requires Account ID configuration. Please use Vercel or Netlify for 1-click deploys." },
            { status: 501 }
        );

    } catch (error) {
        console.error("Cloudflare deployment error:", error);
        return NextResponse.json(
            { error: "Internal server error" },
            { status: 500 }
        );
    }
}

import { Metadata } from "next";
import { currentUser } from "@/modules/auth/actions";
import { getUserProfileStats } from "@/modules/profile/actions";
import KPIStats from "@/modules/profile/components/KPIStats";
import ContributionHeatmap from "@/modules/profile/components/ContributionHeatmap";
import UsageAnalytics from "@/modules/profile/components/UsageAnalytics";
import RecentActivity from "@/modules/profile/components/RecentActivity";
import { QuickActions } from "@/modules/profile/components/SidebarWidgets";
import HeaderNewProjectButton from "@/modules/profile/components/HeaderNewProjectButton";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Search, Bell, Settings, LogOut } from "lucide-react";
import Image from "next/image";
import { Button } from "@/components/ui/button";
import CompactProjectTable from "@/modules/profile/components/CompactProjectTable";
import { deleteProjectById, duplicateProjectById, editProjectById } from "@/modules/dashboard/actions";
import EmptyState from "@/modules/dashboard/components/empty-state";
import LogoutButton from "@/modules/auth/components/logout-button";

export const metadata: Metadata = {
    title: "Profile Dashboard | Editron",
    description: "User profile analytics and dashboard",
};

export default async function ProfilePage() {
    const user = await currentUser();
    if (!user?.id) {
        return <div className="p-8 text-center text-muted-foreground">Please log in to view your profile.</div>;
    }

    // Optimization: Pass user.id directly to avoid re-fetching auth
    const stats = await getUserProfileStats(user.id);

    if (!stats) {
        return <div className="p-8 text-center text-muted-foreground">Error loading stats.</div>;
    }

    return (
        <div className="min-h-screen bg-background text-foreground font-sans pb-8">

            {/* Top Navigation Wrapper for Profile Context */}
            <header className="sticky top-0 z-30 flex h-16 items-center border-b border-border/50 bg-background/80 backdrop-blur-xl px-6 justify-between">
                <div className="flex items-center gap-4 w-full max-w-xl">
                    <h1 className="text-xl font-bold tracking-tight mr-4 hidden md:block">Profile</h1>
                    <div className="relative w-full"></div>
                </div>

                <div className="flex items-center gap-4">
                    <HeaderNewProjectButton />
                    <div className="h-8 w-8 rounded-full bg-gradient-to-tr from-purple-500 to-blue-500 p-[1px]">
                        <div className="h-full w-full rounded-full bg-background flex items-center justify-center overflow-hidden">
                            <Image src={user.image || "/placeholder.svg"} alt="User" width={32} height={32} className="object-cover" />
                        </div>
                    </div>
                </div>
            </header>

            <main className="container mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-8 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

                {/* User Header */}
                <div className="flex flex-col md:flex-row items-start md:items-center gap-6 mb-8">
                    <div className="relative group">
                        <div className="absolute -inset-0.5 bg-gradient-to-r from-pink-600 to-purple-600 rounded-full opacity-75 blur group-hover:opacity-100 transition duration-500"></div>
                        <div className="relative h-24 w-24 rounded-full overflow-hidden border-2 border-background">
                            <Image src={user.image || "/placeholder.svg"} alt={user.name || "User"} width={96} height={96} className="object-cover" />
                        </div>
                        <div className="absolute bottom-0 right-0 h-6 w-6 bg-green-500 border-2 border-background rounded-full" title="Online" />
                    </div>

                    <div className="flex-1">
                        <div className="flex items-center gap-3 mb-1">
                            <h2 className="text-3xl font-bold tracking-tight">{user.name}</h2>
                        </div>
                        <p className="text-muted-foreground flex items-center gap-2 mt-1">
                            {user.email}
                        </p>
                    </div>

                    <div className="flex gap-3">
                        <LogoutButton>
                            <Button variant="outline" className="gap-2 text-red-500 border-red-500/20 hover:bg-red-500/10 hover:border-red-500/50 hover:text-red-600">
                                <LogOut className="w-4 h-4" />
                                Logout
                            </Button>
                        </LogoutButton>
                    </div>
                </div>

                {/* 2. KPI Stats */}
                <KPIStats stats={stats} />

                {/* 3. Heatmap */}
                <ContributionHeatmap data={stats.heatmapData} />

                <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
                    {/* Main Content Column */}
                    <div className="xl:col-span-2 space-y-8">

                        {/* 4. Analytics */}
                        <UsageAnalytics activityData={stats.heatmapData} techStack={stats.techStackDistribution} />

                        {/* 6. Running Environments & AI Insights removed as per request */}

                        {/* Projects Tabs */}
                        <Tabs defaultValue="all" className="w-full">
                            <div className="flex items-center justify-between mb-4">
                                <h3 className="text-xl font-bold">Projects</h3>
                                <TabsList>
                                    <TabsTrigger value="all">All</TabsTrigger>
                                    <TabsTrigger value="starred">Starred</TabsTrigger>
                                </TabsList>
                            </div>
                            <TabsContent value="all" className="mt-0">
                                {stats.playgrounds.length > 0 ? (
                                    <CompactProjectTable
                                        projects={stats.playgrounds}
                                        onDeleteProject={deleteProjectById}
                                        onUpdateProject={editProjectById}
                                        onDuplicateProject={duplicateProjectById}
                                    />
                                ) : (
                                    <div className="bg-card border border-border/50 rounded-xl p-8">
                                        <EmptyState />
                                    </div>
                                )}
                            </TabsContent>
                            <TabsContent value="starred" className="mt-0">
                                {stats.playgrounds.filter((p: any) => p.Starmark?.length > 0 && p.Starmark[0].isMarked).length > 0 ? (
                                    <CompactProjectTable
                                        projects={stats.playgrounds.filter((p: any) => p.Starmark?.length > 0 && p.Starmark[0].isMarked)}
                                        onDeleteProject={deleteProjectById}
                                        onUpdateProject={editProjectById}
                                        onDuplicateProject={duplicateProjectById}
                                    />
                                ) : (
                                    <div className="bg-card border border-border/50 rounded-xl p-8 text-center text-muted-foreground">
                                        No starred projects yet.
                                    </div>
                                )}
                            </TabsContent>
                        </Tabs>

                    </div>

                    {/* Sidebar Column */}
                    <div className="space-y-8">
                        {/* 9. Quick Actions */}
                        <QuickActions />

                        {/* H. Recent Activity */}
                        <RecentActivity activities={stats.recentActivity} />
                    </div>
                </div>

            </main>
        </div>
    );
}

"use client";

import { useSearchParams } from "next/navigation";
import { Copy, ExternalLink, RefreshCw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useState, useRef } from "react";
import { toast } from "sonner";

export default function PreviewPage() {
    const searchParams = useSearchParams();
    const url = searchParams.get("url"); // Gets the 'url' query parameter
    const [iframeKey, setIframeKey] = useState(0); // For forcing iframe reload

    const handleCopyUrl = () => {
        if (url) {
            navigator.clipboard.writeText(url);
            toast.success("URL copied to clipboard");
        }
    };

    const handleRefresh = () => {
        setIframeKey(prev => prev + 1);
    };

    const handleOpenOriginal = () => {
        if (url) {
            window.open(url, '_blank');
        }
    }


    if (!url) {
        return (
            <div className="flex items-center justify-center h-screen bg-neutral-950 text-neutral-400">
                <p>No URL provided for preview.</p>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-screen bg-neutral-950">
            {/* Navbar / Address Bar */}
            <div className="flex items-center gap-2 px-4 py-2 bg-neutral-900 border-b border-neutral-800">
                <Button variant="ghost" size="icon" onClick={handleRefresh} title="Refresh">
                    <RefreshCw size={16} />
                </Button>

                <div className="flex-1 max-w-3xl relative">
                    <Input
                        value={url}
                        readOnly
                        className="w-full h-8 pl-3 pr-8 bg-neutral-800 border-neutral-700 text-neutral-300 text-sm focus-visible:ring-1 focus-visible:ring-neutral-600"
                    />
                </div>

                <Button variant="ghost" size="icon" onClick={handleCopyUrl} title="Copy URL">
                    <Copy size={16} />
                </Button>
                <Button variant="ghost" size="icon" onClick={handleOpenOriginal} title="Open directly">
                    <ExternalLink size={16} />
                </Button>
            </div>

            {/* Preview Iframe */}
            <div className="flex-1 relative bg-white">
                <iframe
                    key={iframeKey}
                    src={url}
                    className="absolute inset-0 w-full h-full border-none"
                    title="Full Screen Preview"
                    sandbox="allow-forms allow-modals allow-popups allow-presentation allow-same-origin allow-scripts"
                    allow="accelerometer; camera; encrypted-media; geolocation; gyroscope; microphone; midi; clipboard-read; clipboard-write;"
                />
            </div>
        </div>
    );
}

import NextAuth from "next-auth"
import { PrismaAdapter } from "@auth/prisma-adapter"

import authConfig from "./auth.config"
import { db } from "./lib/db";
import { getAccountByUserId, getUserById } from "./lib/user-data";





export const { auth, handlers, signIn, signOut } = NextAuth({
  callbacks: {
    /**
     * Handle user creation and account linking after a successful sign-in
     */
    async signIn({ user, account }) {
      if (!user || !account) return false;

      // Check if the user already exists
      const existingUser = await db.user.findUnique({
        where: { email: user.email! },
      });

      // If user does not exist, create a new one
      if (!existingUser) {
        const newUser = await db.user.create({
          data: {
            email: user.email!,
            name: user.name,
            image: user.image,

            accounts: {
              // @ts-expect-error
              create: {
                type: account.type,
                provider: account.provider,
                providerAccountId: account.providerAccountId,
                refreshToken: account.refresh_token,
                accessToken: account.access_token,
                expiresAt: account.expires_at,
                tokenType: account.token_type,
                scope: account.scope,
                idToken: account.id_token,
                sessionState: account.session_state,
              },
            },
          },
        });

        if (!newUser) return false; // Return false if user creation fails
      } else {
        // Link the account if user exists
        const existingAccount = await db.account.findUnique({
          where: {
            provider_providerAccountId: {
              provider: account.provider,
              providerAccountId: account.providerAccountId,
            },
          },
        });

        // If the account does not exist, create it
        if (!existingAccount) {
          await db.account.create({
            data: {
              userId: existingUser.id,
              type: account.type,
              provider: account.provider,
              providerAccountId: account.providerAccountId,
              refreshToken: account.refresh_token,
              accessToken: account.access_token,
              expiresAt: account.expires_at,
              tokenType: account.token_type,
              scope: account.scope,
              idToken: account.id_token,
              // @ts-expect-error
              sessionState: account.session_state,
            },
          });
        } else {
          // Update the access token and other details for existing accounts
          await db.account.update({
            where: { id: existingAccount.id },
            data: {
              accessToken: account.access_token,
              refreshToken: account.refresh_token,
              expiresAt: account.expires_at,
              scope: account.scope,
              idToken: account.id_token,
              // @ts-expect-error
              sessionState: account.session_state,
            }
          });
        }
      }

      return true;
    },

    async jwt({ token}) {
      if (!token.sub) return token;

      // Optimization: If token already has role and picture, skip DB call
      if (token.role && token.picture) {
        return token;
      }

      const existingUser = await getUserById(token.sub)

      if (!existingUser) return token;


      token.name = existingUser.name;
      token.email = existingUser.email;
      token.role = existingUser.role;
      token.picture = existingUser.image; // Add image to token

      return token;
    },

    async session({ session, token }) {
      // Attach the user ID from the token to the session
      if (token.sub && session.user) {
        session.user.id = token.sub
      }

      if (token.sub && session.user) {
        session.user.role = token.role
      }

      // Add name and image to session
      if (session.user) {
        session.user.name = token.name;
        session.user.image = token.picture as string | null | undefined;
      }

      return session;
    },
  },

  secret: process.env.AUTH_SECRET,
  adapter: PrismaAdapter(db),
  session: { strategy: "jwt" },
  ...authConfig,
})

"use client";

import { TemplateOption } from "@/lib/constants/templates";
import {
    Code,
    Server,
    Globe,
    Terminal,
    Star,
    ArrowRight,
    Check
} from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

interface TemplateCardProps {
    template: TemplateOption;
    featured?: boolean;
}

export function TemplateCard({ template, featured = false }: TemplateCardProps) {
    const Icon = template.category === "frontend" ? Code :
        template.category === "backend" ? Server :
            template.category === "fullstack" ? Globe :
                Terminal;

    const categoryColor = template.category === "frontend" ? "text-blue-500" :
        template.category === "backend" ? "text-green-500" :
            template.category === "fullstack" ? "text-purple-500" :
                "text-orange-500";

    return (
        <div className={cn(
            "group relative flex flex-col p-6 rounded-2xl border bg-card hover:shadow-lg transition-all duration-300",
            featured ? "border-primary/20 bg-primary/5" : "border-border"
        )}>
            {/* Header */}
            <div className="flex items-start justify-between mb-4">
                <div
                    className="relative w-12 h-12 flex items-center justify-center rounded-xl transition-transform group-hover:scale-110"
                    style={{ backgroundColor: `${template.color}15` }}
                >
                    <Image
                        src={template.icon}
                        alt={template.name}
                        width={28}
                        height={28}
                        className="object-contain"
                    />
                </div>
                <div className="flex gap-1">
                    {Array(template.popularity).fill(0).map((_, i) => (
                        <Star key={i} size={12} className="fill-yellow-400 text-yellow-400" />
                    ))}
                </div>
            </div>

            {/* Content */}
            <div className="flex-1">
                <div className="flex items-center gap-2 mb-2">
                    <h3 className="font-bold text-lg">{template.name}</h3>
                    <Icon size={14} className={categoryColor} />
                </div>

                <p className="text-sm text-muted-foreground mb-4 line-clamp-2">
                    {template.description}
                </p>

                {/* Tags */}
                <div className="flex flex-wrap gap-2 mb-4">
                    {template.tags.slice(0, 3).map(tag => (
                        <Badge key={tag} variant="secondary" className="text-[10px] h-5 px-2">
                            {tag}
                        </Badge>
                    ))}
                </div>
            </div>

            {/* Footer */}
            <div className="mt-auto pt-4 flex items-center justify-between border-t border-dashed">
                <span className="text-xs text-muted-foreground font-medium uppercase tracking-wider">
                    {template.category}
                </span>

                <Link href="/dashboard">
                    <Button size="sm" variant="ghost" className="h-8 px-2 text-primary hover:text-primary hover:bg-primary/10 group/btn">
                        Use Template
                        <ArrowRight size={14} className="ml-1 transition-transform group-hover/btn:translate-x-1" />
                    </Button>
                </Link>
            </div>

            {/* Hover Gradient Border */}
            <div
                className="absolute inset-0 rounded-2xl border-2 border-transparent group-hover:border-primary/10 pointer-events-none transition-colors"
                aria-hidden="true"
            />
        </div>
    );
}

'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { Button } from '@/components/ui/button';
import {
    ChevronLeftIcon,
    GithubIcon,
    Chrome,
} from 'lucide-react';
import { cn } from '@/lib/utils';
import Link from 'next/link';
import Image from 'next/image';

interface EditronAuthPageProps {
    onGoogleSignIn: () => Promise<void>;
    onGithubSignIn: () => Promise<void>;
}

export function EditronAuthPage({ onGoogleSignIn, onGithubSignIn }: EditronAuthPageProps) {
    return (
        <main className="relative md:h-screen md:overflow-hidden lg:grid lg:grid-cols-2">
            {/* Left Side - Branding & Testimonial */}
            <div className="bg-muted/60 relative hidden h-full flex-col border-r p-10 lg:flex">
                <div className="from-background absolute inset-0 z-10 bg-gradient-to-t to-transparent" />
                <div className="z-10 flex items-center gap-3">
                    <Image src="/logo.svg" alt="Editron Logo" width={32} height={32} className="w-8 h-8" />
                    <p className="text-xl font-bold">Editron</p>
                </div>
                <div className="z-10 mt-auto">
                    <blockquote className="space-y-2">
                        <p className="text-xl">
                            &ldquo;Editron has revolutionized my development workflow.
                            Code anywhere, anytime, with zero setup.&rdquo;
                        </p>
                        <footer className="font-mono text-sm font-semibold">
                            ~ Developer
                        </footer>
                    </blockquote>
                </div>
                <div className="absolute inset-0">
                    <FloatingPaths position={1} />
                    <FloatingPaths position={-1} />
                </div>
            </div>

            {/* Right Side - Auth Form */}
            <div className="relative flex min-h-screen flex-col justify-center p-4">
                {/* Background Gradients with Red Accent */}
                <div
                    aria-hidden
                    className="absolute inset-0 isolate contain-strict -z-10 opacity-60"
                >
                    <div className="absolute top-0 right-0 h-[800px] w-[600px] -translate-y-[350px] rounded-full bg-gradient-to-br from-red-500/10 via-rose-500/5 to-transparent blur-3xl" />
                    <div className="absolute top-1/2 left-0 h-[600px] w-[400px] -translate-x-1/2 rounded-full bg-gradient-to-tr from-amber-500/5 via-red-500/10 to-transparent blur-3xl" />
                    <div className="bg-[radial-gradient(68.54%_68.72%_at_55.02%_31.46%,--theme(--color-foreground/.06)_0,hsla(0,0%,55%,.02)_50%,--theme(--color-foreground/.01)_80%)] absolute top-0 right-0 h-320 w-140 -translate-y-87.5 rounded-full" />
                </div>

                {/* Back to Home Button */}
                <Button variant="ghost" className="absolute top-7 left-5" asChild>
                    <Link href="/">
                        <ChevronLeftIcon className='size-4 me-2' />
                        Home
                    </Link>
                </Button>

                {/* Auth Form Container */}
                <div className="mx-auto space-y-6 sm:w-sm">
                    {/* Mobile Logo */}
                    <div className="flex items-center gap-3 lg:hidden">
                        <div className="relative">
                            <div className="absolute inset-0 bg-gradient-to-r from-red-500/20 to-rose-500/20 blur-xl rounded-full"></div>
                            <Image src="/logo.svg" alt="Editron Logo" width={32} height={32} className="w-8 h-8 relative z-10" />
                        </div>
                        <p className="text-xl font-bold">Editron</p>
                    </div>

                    {/* Header */}
                    <div className="flex flex-col space-y-3">
                        <h1 className="font-heading text-3xl md:text-4xl font-black tracking-tight">
                            Welcome to <span className="bg-clip-text text-transparent bg-gradient-to-r from-red-500 via-rose-500 to-amber-500">Editron</span>
                        </h1>
                        <p className="text-muted-foreground text-base">
                            Sign in to start coding with intelligence
                        </p>

                        {/* Status Badge */}
                        <div className="inline-flex items-center rounded-full border border-red-500/20 bg-red-500/10 px-3 py-1 text-sm text-red-500 backdrop-blur-md w-fit">
                            <span className="flex h-2 w-2 rounded-full bg-red-500 mr-2 animate-pulse"></span>
                            <span className="font-medium">Secure Authentication</span>
                        </div>
                    </div>

                    {/* Social Sign In Buttons */}
                    <div className="space-y-3 relative">
                        {/* Subtle glow behind buttons */}
                        <div className="absolute -inset-2 bg-gradient-to-r from-red-500/5 via-rose-500/5 to-amber-500/5 rounded-2xl blur-xl opacity-0 group-hover:opacity-100 transition-opacity"></div>

                        <form action={onGoogleSignIn}>
                            <Button
                                type="submit"
                                size="lg"
                                className="w-full h-12 rounded-xl bg-white dark:bg-white text-gray-900 dark:text-gray-900 hover:bg-red-50 dark:hover:bg-red-50 border border-gray-200 dark:border-gray-200 hover:border-red-500/50 transition-all duration-300 group relative z-10 shadow-sm"
                            >
                                <Chrome className='size-5 me-2 group-hover:text-red-500 transition-colors' />
                                <span className="font-semibold">Continue with Google</span>
                            </Button>
                        </form>
                        <form action={onGithubSignIn}>
                            <Button
                                type="submit"
                                size="lg"
                                className="w-full h-12 rounded-xl bg-white dark:bg-white text-gray-900 dark:text-gray-900 hover:bg-red-50 dark:hover:bg-red-50 border border-gray-200 dark:border-gray-200 hover:border-red-500/50 transition-all duration-300 group relative z-10 shadow-sm"
                            >
                                <GithubIcon className='size-5 me-2 group-hover:text-red-500 transition-colors' />
                                <span className="font-semibold">Continue with GitHub</span>
                            </Button>
                        </form>
                    </div>

                    {/* Terms & Privacy */}
                    <p className="text-muted-foreground mt-8 text-sm text-center">
                        By continuing, you agree to our{' '}
                        <a
                            href="#"
                            className="hover:text-red-500 underline underline-offset-4 transition-colors"
                        >
                            Terms of Service
                        </a>{' '}
                        and{' '}
                        <a
                            href="#"
                            className="hover:text-red-500 underline underline-offset-4 transition-colors"
                        >
                            Privacy Policy
                        </a>
                        .
                    </p>
                </div>
            </div>
        </main>
    );
}

function FloatingPaths({ position }: { position: number }) {
    const paths = Array.from({ length: 36 }, (_, i) => ({
        id: i,
        d: `M-${380 - i * 5 * position} -${189 + i * 6}C-${380 - i * 5 * position
            } -${189 + i * 6} -${312 - i * 5 * position} ${216 - i * 6} ${152 - i * 5 * position
            } ${343 - i * 6}C${616 - i * 5 * position} ${470 - i * 6} ${684 - i * 5 * position
            } ${875 - i * 6} ${684 - i * 5 * position} ${875 - i * 6}`,
        width: 1 + i * 0.05, // Increased stroke width
    }));

    return (
        <div className="pointer-events-none absolute inset-0">
            <svg
                className="h-full w-full"
                viewBox="0 0 696 316"
                fill="none"
            >
                <defs>
                    {/* Vibrant Red gradient for the paths */}
                    <linearGradient id="redGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                        <stop offset="0%" stopColor="#ef4444" stopOpacity="0.9" />
                        <stop offset="50%" stopColor="#f43f5e" stopOpacity="0.8" />
                        <stop offset="100%" stopColor="#f59e0b" stopOpacity="0.7" />
                    </linearGradient>
                </defs>
                <title>Background Animation</title>
                {paths.map((path) => (
                    <motion.path
                        key={path.id}
                        d={path.d}
                        stroke="url(#redGradient)"
                        strokeWidth={path.width}
                        strokeOpacity={0.4 + path.id * 0.02}
                        initial={{ pathLength: 0.3, opacity: 1 }}
                        animate={{
                            pathLength: 1,
