"use client";

import * as React from "react";
import {
    CommandDialog,
    CommandEmpty,
    CommandGroup,
    CommandInput,
    CommandItem,
    CommandList,
    CommandSeparator,
} from "@/components/ui/command";
import {
    Save,
    Download,
    Eye,
    EyeOff,
    Bot,
    Settings,
    XCircle,
    PanelLeftClose,
    Palette,
} from "lucide-react";
import { FileIcon } from "./file-icon";
import type {
    TemplateFile,
    TemplateFolder,
} from "@/modules/playground/lib/path-to-json";

interface CommandPaletteProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    templateData: TemplateFolder | null;
    onFileSelect: (file: TemplateFile) => void;
    onSave: () => void;
    onSaveAll: () => void;
    onDownload: () => void;
    onTogglePreview: () => void;
    onToggleAI: () => void;
    onToggleSidebar: () => void;
    onOpenSettings: () => void;
    onCloseAllFiles: () => void;
    isPreviewVisible: boolean;
}

function collectFiles(
    items: (TemplateFile | TemplateFolder)[],
    parentPath: string = ""
): { file: TemplateFile; path: string }[] {
    const result: { file: TemplateFile; path: string }[] = [];
    for (const item of items) {
        if ("folderName" in item) {
            const folderPath = parentPath
                ? `${parentPath}/${item.folderName}`
                : item.folderName;
            result.push(...collectFiles(item.items, folderPath));
        } else {
            const filePath = parentPath
                ? `${parentPath}/${item.filename}.${item.fileExtension}`
                : `${item.filename}.${item.fileExtension}`;
            result.push({ file: item, path: filePath });
        }
    }
    return result;
}

export function CommandPalette({
    open,
    onOpenChange,
    templateData,
    onFileSelect,
    onSave,
    onSaveAll,
    onDownload,
    onTogglePreview,
    onToggleAI,
    onToggleSidebar,
    onOpenSettings,
    onCloseAllFiles,
    isPreviewVisible,
}: CommandPaletteProps) {
    const files = React.useMemo(
        () => (templateData ? collectFiles(templateData.items) : []),
        [templateData]
    );

    const runAction = (action: () => void) => {
        onOpenChange(false);
        action();
    };

    return (
        <CommandDialog open={open} onOpenChange={onOpenChange}>
            <CommandInput placeholder="Search files and actions..." />
            <CommandList>
                <CommandEmpty>No results found.</CommandEmpty>

                {/* Files */}
                <CommandGroup heading="Files">
                    {files.map(({ file, path }) => (
                        <CommandItem
                            key={path}
                            value={path}
                            onSelect={() => runAction(() => onFileSelect(file))}
                        >
                            <FileIcon extension={file.fileExtension} className="mr-2" />
                            <span className="flex-1">{file.filename}.{file.fileExtension}</span>
                            <span className="text-[10px] text-muted-foreground/60 font-mono">
                                {path}
                            </span>
                        </CommandItem>
                    ))}
                </CommandGroup>

                <CommandSeparator />

                {/* Actions */}
                <CommandGroup heading="Actions">
                    <CommandItem onSelect={() => runAction(onSave)}>
                        <Save className="mr-2 h-4 w-4" />
                        <span className="flex-1">Save</span>
                        <kbd className="text-[10px] px-1.5 py-0.5 rounded border bg-muted font-mono">
                            Ctrl+S
                        </kbd>
                    </CommandItem>
                    <CommandItem onSelect={() => runAction(onSaveAll)}>
                        <Save className="mr-2 h-4 w-4" />
                        <span className="flex-1">Save All</span>
                        <kbd className="text-[10px] px-1.5 py-0.5 rounded border bg-muted font-mono">
                            Ctrl+Shift+S
                        </kbd>
                    </CommandItem>
                    <CommandItem onSelect={() => runAction(onTogglePreview)}>
                        {isPreviewVisible ? (
                            <EyeOff className="mr-2 h-4 w-4" />
                        ) : (
                            <Eye className="mr-2 h-4 w-4" />
                        )}
                        <span className="flex-1">
                            {isPreviewVisible ? "Hide" : "Show"} Preview
                        </span>
                        <kbd className="text-[10px] px-1.5 py-0.5 rounded border bg-muted font-mono">
                            Ctrl+\
                        </kbd>
                    </CommandItem>
                    <CommandItem onSelect={() => runAction(onToggleAI)}>
                        <Bot className="mr-2 h-4 w-4" />
                        <span className="flex-1">Toggle AI Chat</span>
                        <kbd className="text-[10px] px-1.5 py-0.5 rounded border bg-muted font-mono">
                            Ctrl+Shift+A
                        </kbd>
                    </CommandItem>
                    <CommandItem onSelect={() => runAction(onToggleSidebar)}>
                        <PanelLeftClose className="mr-2 h-4 w-4" />
                        <span className="flex-1">Toggle Sidebar</span>
                        <kbd className="text-[10px] px-1.5 py-0.5 rounded border bg-muted font-mono">
                            Ctrl+B
                        </kbd>
                    </CommandItem>
                    <CommandItem onSelect={() => runAction(onDownload)}>
                        <Download className="mr-2 h-4 w-4" />
                        <span className="flex-1">Download Project</span>
                    </CommandItem>
                    <CommandItem onSelect={() => runAction(onCloseAllFiles)}>
                        <XCircle className="mr-2 h-4 w-4" />
                        <span className="flex-1">Close All Files</span>
                    </CommandItem>
                </CommandGroup>

                <CommandSeparator />

                {/* Settings */}
                <CommandGroup heading="Settings">
                    <CommandItem onSelect={() => runAction(onOpenSettings)}>
                        <Settings className="mr-2 h-4 w-4" />
                        <span>AI Settings</span>
                    </CommandItem>
                </CommandGroup>
            </CommandList>
        </CommandDialog>
    );
}

"use client";

import React, { useState } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Loader2, Globe, ArrowRight, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";
import type { TemplateFolder } from "@/modules/playground/lib/path-to-json";

interface DeployDialogProps {
    open: boolean;
    onOpenChange: (open: boolean) => void;
    templateData: TemplateFolder | null;
    projectName?: string;
}

export function DeployDialog({ open, onOpenChange, templateData, projectName }: DeployDialogProps) {
    const [provider, setProvider] = useState<"vercel" | "netlify" | "cloudflare">("vercel");
    const [useMasterKey, setUseMasterKey] = useState(true);
    const [userKey, setUserKey] = useState("");
    const [isDeploying, setIsDeploying] = useState(false);
    const [deployedUrl, setDeployedUrl] = useState("");

    const flattenFileTree = (data: any, parentPath = ""): { path: string; content: string }[] => {
        let files: { path: string; content: string }[] = [];
        if (!data) return files;

        const items = data.items || [];
        for (const item of items) {
            if ("folderName" in item) {
                files = [...files, ...flattenFileTree(item, `${parentPath}${item.folderName}/`)];
            } else {
                const extension = item.fileExtension ? `.${item.fileExtension}` : "";
                files.push({
                    path: `${parentPath}${item.filename}${extension}`,
                    content: item.content
                });
            }
        }
        return files;
    };

    const handleDeploy = async () => {
        if (!useMasterKey && !userKey) {
            toast.error(`Please enter your ${provider === "vercel" ? "Vercel" : provider === "netlify" ? "Netlify" : "Cloudflare"} API key`);
            return;
        }

        if (!templateData) {
            toast.error("No files to deploy");
            return;
        }

        setIsDeploying(true);
        setDeployedUrl("");

        try {
            const flatFiles = flattenFileTree(templateData);

            // We don't deploy node_modules or big cache folders
            const filteredFiles = flatFiles.filter(f => !f.path.startsWith("node_modules/") && !f.path.startsWith(".next/"));

            const res = await fetch(`/api/deploy/${provider}`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    files: filteredFiles,
                    name: projectName,
                    userApiKey: useMasterKey ? undefined : userKey
                })
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Deployment failed");
            }

            setDeployedUrl(data.url.startsWith("http") ? data.url : `https://${data.url}`);
            toast.success("Successfully deployed!");

        } catch (error: any) {
            console.error(error);
            toast.error(error.message || "Failed to deploy. Check your API key or try again.");
        } finally {
            setIsDeploying(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="sm:max-w-[425px]">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Globe className="h-5 w-5 text-muted-foreground" />
                        Deploy to Cloud
                    </DialogTitle>
                    <DialogDescription>
                        Publish your current playground files instantly to a live, public URL.
                    </DialogDescription>
                </DialogHeader>

                {deployedUrl ? (
                    <div className="flex flex-col items-center justify-center py-6 space-y-4">
                        <div className="h-12 w-12 rounded-full bg-green-500/10 flex items-center justify-center">
                            <CheckCircle2 className="h-6 w-6 text-green-500" />
                        </div>
                        <p className="font-medium text-center">Deployment Successful!</p>
                        <a href={deployedUrl} target="_blank" rel="noopener noreferrer" className="text-sm text-blue-500 hover:underline break-all text-center px-4">
                            {deployedUrl}
                        </a>
                        <Button className="w-full mt-4" variant="outline" onClick={() => window.open(deployedUrl, '_blank')}>
                            Visit Site <ArrowRight className="h-4 w-4 ml-2" />
                        </Button>
                    </div>
                ) : (
                    <div className="grid gap-4 py-4">
                        <Tabs value={provider} onValueChange={(v: any) => setProvider(v)}>
                            <TabsList className="grid w-full grid-cols-3">
                                <TabsTrigger value="vercel">Vercel</TabsTrigger>
                                <TabsTrigger value="netlify">Netlify</TabsTrigger>
                                <TabsTrigger value="cloudflare">Cloudflare</TabsTrigger>
                            </TabsList>
                        </Tabs>

                        <div className="rounded-md border p-4 bg-muted/30">
                            <div className="flex items-center justify-between mb-4">
                                <Label className="text-sm font-medium">Authentication Policy</Label>
                            </div>
                            <div className="space-y-4">
                                <div
                                    className={`flex items-start space-x-3 rounded-lg border p-3 cursor-pointer transition-colors ${useMasterKey ? 'bg-background border-primary' : 'hover:bg-muted/50'}`}
                                    onClick={() => setUseMasterKey(true)}
                                >
                                    <div className={`mt-0.5 h-4 w-4 rounded-full border flex items-center justify-center ${useMasterKey ? 'border-primary' : 'border-muted-foreground'}`}>
                                        {useMasterKey && <div className="h-2 w-2 rounded-full bg-primary" />}
                                    </div>
                                    <div>
                                        <p className="text-sm font-medium">Use Editron Deployment</p>
                                        <p className="text-xs text-muted-foreground">Deploy immediately using our master key. Ideal for quick demos.</p>
                                    </div>
                                </div>

                                <div
                                    className={`flex flex-col space-y-2 rounded-lg border p-3 cursor-pointer transition-colors ${!useMasterKey ? 'bg-background border-primary' : 'hover:bg-muted/50'}`}
                                    onClick={() => setUseMasterKey(false)}
                                >
                                    <div className="flex items-start space-x-3 md:items-center">
                                        <div className={`mt-0.5 md:mt-0 h-4 w-4 rounded-full border flex items-center justify-center shrink-0 ${!useMasterKey ? 'border-primary' : 'border-muted-foreground'}`}>
                                            {!useMasterKey && <div className="h-2 w-2 rounded-full bg-primary" />}
                                        </div>
                                        <div>
                                            <p className="text-sm font-medium">Bring Your Own Key</p>
                                            <p className="text-xs text-muted-foreground">Deploy to your personal {provider === 'vercel' ? 'Vercel' : provider === 'netlify' ? 'Netlify' : 'Cloudflare'} account.</p>
                                        </div>
                                    </div>

                                    {!useMasterKey && (
                                        <div className="pl-7 pt-2">
                                            <Input
                                                placeholder={`${provider.charAt(0).toUpperCase() + provider.slice(1)} API Token`}
                                                value={userKey}
                                                onChange={(e) => setUserKey(e.target.value)}
                                                type="password"
                                                autoFocus
                                            />
                                            <p className="text-[10px] text-muted-foreground mt-1.5 ml-1">
                                                Tokens are only used for this deployment and never saved.
                                            </p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>

                        <Button onClick={handleDeploy} disabled={isDeploying} className="w-full">
                            {isDeploying ? (
                                <>
                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    Deploying to {provider === "vercel" ? "Vercel" : provider === "netlify" ? "Netlify" : "Cloudflare"}...
                                </>
                            ) : (
                                `Deploy to ${provider === "vercel" ? "Vercel" : provider === "netlify" ? "Netlify" : "Cloudflare"}`
                            )}
                        </Button>

                        {provider === "cloudflare" && (
                            <p className="text-xs text-amber-500 text-center mt-2">
                                Note: Cloudflare Pages Direct Upload API requires an Account ID in addition to the API Token. We recommend using Vercel or Netlify for quick deploys.
                            </p>
                        )}
                    </div>
                )}
            </DialogContent>
        </Dialog>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import {
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
} from "@/components/ui/sidebar";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Search, Package, Trash2, Download, Loader2 } from "lucide-react";
import { useWebContainer } from "@/modules/webcontainers/hooks/useWebContainer";
import { toast } from "sonner";
import { Badge } from "@/components/ui/badge";

interface NpmSearchResult {
  objects: {
    package: {
      name: string;
      version: string;
      description: string;
      publisher: { username: string; email: string };
    };
  }[];
}

export function PackageManager({
  templateData,
  instance,
}: {
  templateData: any;
  instance: any;
}) {
  const [searchQuery, setSearchQuery] = useState("");
  const [searchResults, setSearchResults] = useState<NpmSearchResult["objects"]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [dependencies, setDependencies] = useState<Record<string, string>>({});
  const [devDependencies, setDevDependencies] = useState<Record<string, string>>({});
  const [loadingPkg, setLoadingPkg] = useState<string | null>(null);

  // Parse package.json
  const parsePackageJson = React.useCallback(() => {
    if (!templateData) return;
    
    // Find package.json
    const findPkg = (items: any[]): any => {
      for (const item of items) {
        if (!("folderName" in item) && item.filename === "package" && item.fileExtension === "json") {
          return item;
        } else if ("folderName" in item) {
          const found = findPkg(item.items);
          if (found) return found;
        }
      }
      return null;
    };

    const pkgFile = findPkg(templateData.items);
    if (pkgFile && pkgFile.content) {
      try {
        const parsed = JSON.parse(pkgFile.content);
        setDependencies(parsed.dependencies || {});
        setDevDependencies(parsed.devDependencies || {});
      } catch (e) {
        console.error("Failed to parse package.json");
      }
    }
  }, [templateData]);

  useEffect(() => {
    parsePackageJson();
  }, [parsePackageJson]);

  const searchNpm = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchQuery.trim()) return;

    setIsSearching(true);
    try {
      const res = await fetch(`https://registry.npmjs.org/-/v1/search?text=${encodeURIComponent(searchQuery)}&size=10`);
      const data = await res.json();
      setSearchResults(data.objects);
    } catch (error) {
      toast.error("Failed to search NPM registry");
    } finally {
      setIsSearching(false);
    }
  };

  const executeCommand = async (command: string, args: string[], pkgName: string) => {
    if (!instance) {
      toast.error("WebContainer is not ready");
      return;
    }

    setLoadingPkg(pkgName);
    try {
      const process = await instance.spawn(command, args);
      const exitCode = await process.exit;

      if (exitCode === 0) {
        toast.success(`Successfully ran: ${command} ${args.join(" ")}`);
        // Refresh dependencies (In a real app we'd let the FileSystem watcher trigger this, but we'll re-parse manual for now if we can)
      } else {
        toast.error(`Command failed with exit code ${exitCode}`);
      }
    } catch (error) {
      console.error(error);
      toast.error("An error occurred executing the command");
    } finally {
      setLoadingPkg(null);
    }
  };

  const handleInstall = (pkgName: string, isDev = false) => {
    const args = ["install", pkgName];
    if (isDev) args.push("-D");
    executeCommand("npm", args, pkgName);
  };

  const handleRemove = (pkgName: string) => {
    executeCommand("npm", ["uninstall", pkgName], pkgName);
  };

  return (
    <SidebarGroup>
      <SidebarGroupLabel className="flex justify-between items-center text-xs uppercase text-muted-foreground font-semibold px-2 py-1.5 h-8">
        Dependencies
      </SidebarGroupLabel>
      <SidebarGroupContent className="p-2 space-y-4">
        
        {/* Search */}
        <form onSubmit={searchNpm} className="flex gap-2">
          <Input 
            placeholder="Search NPM package..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="h-8 text-xs bg-muted/50 focus-visible:ring-1"
          />
          <Button type="submit" size="icon" className="h-8 w-8 shrink-0">
            {isSearching ? <Loader2 className="h-4 w-4 animate-spin" /> : <Search className="h-4 w-4" />}
          </Button>
        </form>

        {/* Search Results */}
        {searchResults.length > 0 && (
          <div className="space-y-2 border-b pb-4">
            <p className="text-xs font-medium text-muted-foreground px-1">Results</p>
            {searchResults.map((result) => (
              <div key={result.package.name} className="flex flex-col gap-1.5 p-2 rounded-md bg-muted/30 border text-xs">
                <div className="flex items-center justify-between">
                  <span className="font-semibold">{result.package.name}</span>
                  <span className="text-[10px] text-muted-foreground">{result.package.version}</span>
                </div>
                <p className="text-[10px] text-muted-foreground line-clamp-1">{result.package.description}</p>
                <div className="flex gap-1.5 mt-1">
                  <Button 
                    size="sm" 
                    variant="default" 
                    className="h-6 text-[10px] px-2 w-full"
                    onClick={() => handleInstall(result.package.name)}
                    disabled={loadingPkg === result.package.name}
                  >
                    {loadingPkg === result.package.name ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : <Download className="h-3 w-3 mr-1" />}
                    Add
                  </Button>
                  <Button 
                    size="sm" 
                    variant="outline" 
                    className="h-6 text-[10px] px-2 w-full"
                    onClick={() => handleInstall(result.package.name, true)}
                    disabled={loadingPkg === result.package.name}
                  >
                    Add -D
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Installed Dependencies */}
        <div className="space-y-3">
          {Object.keys(dependencies).length > 0 && (
            <div>
              <p className="text-xs font-medium text-muted-foreground px-1 py-1">Dependencies</p>
              {Object.entries(dependencies).map(([name, version]) => (
                 <div key={name} className="group flex items-center justify-between px-2 py-1.5 rounded-md hover:bg-muted/50 cursor-pointer text-xs">
                 <div className="flex items-center gap-2 overflow-hidden">
                   <Package className="h-3.5 w-3.5 shrink-0 text-muted-foreground/70" />
                   <span className="truncate">{name}</span>
                 </div>
                 <div className="flex items-center gap-2">
                   <Badge variant="secondary" className="text-[9px] px-1 py-0 h-4 font-mono font-normal">
                     {version}
                   </Badge>
                   <Button
                      size="icon"
                      variant="ghost"
                      className="h-5 w-5 opacity-0 group-hover:opacity-100 transition-opacity"
                      onClick={() => handleRemove(name)}
                      disabled={loadingPkg === name}
                    >
                      {loadingPkg === name ? <Loader2 className="h-3 w-3 animate-spin" /> : <Trash2 className="h-3 w-3 text-red-500 hover:text-red-600" />}
                    </Button>
                 </div>
               </div>
              ))}
            </div>
          )}

          {Object.keys(devDependencies).length > 0 && (
            <div>
              <p className="text-xs font-medium text-muted-foreground px-1 py-1">Dev Dependencies</p>
              {Object.entries(devDependencies).map(([name, version]) => (
                <div key={name} className="group flex items-center justify-between px-2 py-1.5 rounded-md hover:bg-muted/50 cursor-pointer text-xs">
                  <div className="flex items-center gap-2 overflow-hidden">
                    <Package className="h-3.5 w-3.5 shrink-0 text-muted-foreground/70" />
                    <span className="truncate">{name}</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge variant="secondary" className="text-[9px] px-1 py-0 h-4 font-mono font-normal">
                      {version}
                    </Badge>
                    <Button
                      size="icon"
                      variant="ghost"
                      className="h-5 w-5 opacity-0 group-hover:opacity-100 transition-opacity"
                      onClick={() => handleRemove(name)}
                      disabled={loadingPkg === name}
                    >
                      {loadingPkg === name ? <Loader2 className="h-3 w-3 animate-spin" /> : <Trash2 className="h-3 w-3 text-red-500 hover:text-red-600" />}
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
          
          {Object.keys(dependencies).length === 0 && Object.keys(devDependencies).length === 0 && (
            <p className="text-[11px] text-muted-foreground px-2">No dependencies found in package.json</p>
          )}
        </div>
      </SidebarGroupContent>
    </SidebarGroup>
  );
}

"use client";
import { useRef, useEffect, useCallback, useState } from "react";
import Editor, { type Monaco } from "@monaco-editor/react";
import {
  configureMonaco,
  defaultEditorOptions,
  getEditorLanguage,
} from "@/modules/playground/lib/editor-config";
import type { TemplateFile } from "@/modules/playground/lib/path-to-json";
import { useAI } from "@/modules/playground/hooks/useAI";

import prettier from "prettier/standalone";
import prettierPluginBabel from "prettier/plugins/babel";
import prettierPluginEstree from "prettier/plugins/estree";
import prettierPluginHtml from "prettier/plugins/html";
import prettierPluginPostcss from "prettier/plugins/postcss";
import prettierPluginTypeScript from "prettier/plugins/typescript";

import { MonacoBinding } from "y-monaco";
import { fetchCollabToken, getOrCreateYDoc, destroyYDoc } from "@/lib/yjs";
import { useParams } from "next/navigation";
import { useSession } from "next-auth/react";

export interface PlaygroundEditorProps {
  activeFile: TemplateFile | undefined;
  content: string;
  onContentChange: (value: string) => void;
  onCursorChange?: (line: number, col: number) => void;
}

let inlineProviderDisposable: any = null;
let formatterDisposable: any = null;

const PlaygroundEditor = ({
  activeFile,
  content,
  onContentChange,
  onCursorChange,
}: PlaygroundEditorProps) => {
  const params = useParams();
  const playgroundId = params?.id as string;
  const editorRef = useRef<any>(null);
  const monacoRef = useRef<Monaco | null>(null);
  const debounceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const bindingRef = useRef<any>(null);
  const { data: session } = useSession();
  const [isMounted, setIsMounted] = useState(false);

  const handleEditorDidMount = (editor: any, monaco: Monaco) => {
    editorRef.current = editor;
    monacoRef.current = monaco;
    setIsMounted(true);

    editor.updateOptions({
      ...defaultEditorOptions,
      inlineSuggest: { enabled: true },
      formatOnSave: true,
    });

    // Cursor position tracking for status bar
    editor.onDidChangeCursorPosition((e: any) => {
      onCursorChange?.(e.position.lineNumber, e.position.column);
    });

    configureMonaco(monaco);
    updateEditorLanguage();
    registerInlineCompletionProvider(monaco);
    registerPrettierFormatter(monaco);
  };

  const registerPrettierFormatter = (monaco: Monaco) => {
    if (formatterDisposable) {
      formatterDisposable.dispose();
      formatterDisposable = null;
    }

    const languages = ["javascript", "typescript", "html", "css", "json"];

    formatterDisposable = monaco.languages.registerDocumentFormattingEditProvider(languages, {
      async provideDocumentFormattingEdits(model, options, token) {
        const text = model.getValue();
        const languageId = model.getLanguageId();

        // Map monaco language ids to prettier parsers
        let parser = "babel";
        const plugins = [
          prettierPluginBabel,
          prettierPluginEstree,
          prettierPluginHtml,
          prettierPluginPostcss,
          prettierPluginTypeScript
        ];

        switch (languageId) {
          case "javascript":
            parser = "babel";
            break;
          case "typescript":
            parser = "typescript";
            break;
          case "html":
            parser = "html";
            break;
          case "css":
            parser = "css";
            break;
          case "json":
            parser = "json";
            // Prettier json parser is in babel/estree usually for standalone or it needs its own.
            // Using babel as a fallback, though technically prettier exposes a separate json plugin if needed.
            // But usually babel handles json well enough in browser standalone.
            break;
          default:
            return [];
        }

        try {
          const formatted = await prettier.format(text, {
            parser,
            plugins,
            singleQuote: false,
            tabWidth: options.tabSize || 2,
            useTabs: options.insertSpaces === false,
          });

          return [
            {
              range: model.getFullModelRange(),
              text: formatted,
            },
          ];
        } catch (error) {
          console.error("Prettier formatting error:", error);
          return [];
        }
      }
    });
  };

  const registerInlineCompletionProvider = (monaco: Monaco) => {
    // Dispose previous provider if exists
    if (inlineProviderDisposable) {
      inlineProviderDisposable.dispose();
      inlineProviderDisposable = null;
    }

    inlineProviderDisposable = monaco.languages.registerInlineCompletionsProvider(
      { pattern: "**" },
      {
        provideInlineCompletions: async (model, position, context, token) => {
          // Check if inline suggestions are enabled
          if (!useAI.getState().inlineSuggestionsEnabled) return { items: [] };
          if (token.isCancellationRequested) return { items: [] };

          // Gather context: lines around cursor
          const lineCount = model.getLineCount();
          const currentLine = model.getLineContent(position.lineNumber);
          const textBeforeCursor = currentLine.substring(0, position.column - 1);

          // Don't trigger on empty lines or very short input
          if (textBeforeCursor.trim().length < 3) return { items: [] };

          // Build context from surrounding lines
          const startLine = Math.max(1, position.lineNumber - 20);
          const endLine = Math.min(lineCount, position.lineNumber + 5);
          const contextLines: string[] = [];
          for (let i = startLine; i <= endLine; i++) {
            if (i === position.lineNumber) {
              contextLines.push(textBeforeCursor + "█"); // cursor marker
            } else {
              contextLines.push(model.getLineContent(i));
            }
          }

          const prompt = contextLines.join("\n");
          const language = model.getLanguageId();

          // Wait with debounce (return promise that resolves after delay)
          await new Promise<void>((resolve) => {
            if (debounceTimerRef.current) clearTimeout(debounceTimerRef.current);
            debounceTimerRef.current = setTimeout(resolve, 1500);
          });

          if (token.isCancellationRequested) return { items: [] };

          try {
            const { provider, getUserApiKey } = useAI.getState();
            const userApiKey = getUserApiKey();

            const res = await fetch("/api/completion", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                prompt,
                language,
                provider,
                userApiKey: userApiKey || undefined,
              }),
            });

            if (!res.ok) return { items: [] };

            const data = await res.json();
            const completion = data.completion?.trim();

            if (!completion) return { items: [] };

            // Clean up completion - remove markdown code fences if present
            let cleanCompletion = completion;
            if (cleanCompletion.startsWith("```")) {
              const lines = cleanCompletion.split("\n");
              lines.shift(); // remove opening fence
              if (lines[lines.length - 1]?.trim() === "```") lines.pop();
              cleanCompletion = lines.join("\n");
            }

            return {
              items: [
                {
                  insertText: cleanCompletion,
                  range: {
                    startLineNumber: position.lineNumber,
                    startColumn: position.column,
                    endLineNumber: position.lineNumber,
                    endColumn: position.column,
                  },
                },
              ],
            };
          } catch (error) {
            console.warn("Inline completion error:", error);
            return { items: [] };
          }
        },

        freeInlineCompletions: () => { },
      }
    );
  };

  const updateEditorLanguage = () => {
    if (!activeFile || !monacoRef.current || !editorRef.current) return;
    const model = editorRef.current.getModel();
    if (!model) return;

    const language = getEditorLanguage(activeFile.fileExtension || "");
    try {
      monacoRef.current.editor.setModelLanguage(model, language);
    } catch (error) {
      console.warn("Failed to set editor language:", error);
    }
  };

  useEffect(() => {
    updateEditorLanguage();
  }, [activeFile]);

  // Bind Yjs to Monaco
  useEffect(() => {
    if (!activeFile || !monacoRef.current || !editorRef.current || !playgroundId) return;

    // Check if collaboration enabled ideally... For now we bind unconditionally or check session docs.
    // If the room doesn't exist on server, y-websocket will just act locally until server connects.
    const model = editorRef.current.getModel();
    if (!model) return;

    let disposed = false;
    let awarenessCleanup = () => {};

    void (async () => {
      try {
        const token = await fetchCollabToken(playgroundId);
        if (disposed) return;

        const { doc, provider } = getOrCreateYDoc(playgroundId, token);
        // Use file id if available (contains full path), otherwise fallback to filename+ext
        const fileId = (activeFile as any)?.id;
        const ext = activeFile.fileExtension ? `.${activeFile.fileExtension}` : "";
        const fileKey = fileId || `${activeFile.filename}${ext}`;

        const yText = doc.getText(fileKey);

        // Initial content population if empty
        if (yText.length === 0 && content) {
          yText.insert(0, content);
        }

        if (bindingRef.current) {
          bindingRef.current.destroy();
        }

        const binding = new MonacoBinding(
          yText,
          model,
          new Set([editorRef.current]),
          provider.awareness
        );

        const userColor = session?.user?.email ? "#" + Math.floor(Math.abs(Math.sin(session.user.email.charCodeAt(0)) * 16777215)).toString(16).padEnd(6, '0') : "#30bced";

        provider.awareness.setLocalStateField('user', {
          name: session?.user?.name || "Anonymous",
          color: userColor
        });

        const handleAwarenessUpdate = () => {
          const styleId = "yjs-awareness-styles";
          let styleEl = document.getElementById(styleId);
          if (!styleEl) {
            styleEl = document.createElement("style");
            styleEl.id = styleId;
            document.head.appendChild(styleEl);
          }

          const states = Array.from(provider.awareness.getStates().entries() as any);
          let css = "";

          for (const [clientId, state] of states as [number, any][]) {
            if (state.user) {
              const color = state.user.color || "orange";
              const name = state.user.name || "Anonymous";

              css += `
                .yRemoteSelection-${clientId} {
                  background-color: ${color}40; /* 40 hex is 25% opacity */
                }
                .yRemoteSelectionHead-${clientId} {
                  border-left: 2px solid ${color};
                  border-top: 2px solid ${color};
                  border-bottom: 2px solid ${color};
                }
                .yRemoteSelectionHead-${clientId}::after {
                  border-color: ${color};
                }
                .yRemoteSelectionHead-${clientId}::before {
                  content: "${name}";
                  position: absolute;
                  top: -18px;
                  left: -2px;
                  font-size: 11px;
                  background-color: ${color};
                  color: white;
                  padding: 1px 4px;
                  border-radius: 2px;
                  white-space: nowrap;
                  pointer-events: none;
                  z-index: 10;
                  font-family: var(--font-inter), sans-serif;
                  opacity: 0;
                  transition: opacity 0.2s ease-in-out;
                }
                .yRemoteSelectionHead-${clientId}:hover::before {
                  opacity: 1;
                }
              `;
            }
          }
          styleEl.innerHTML = css;
        };

        provider.awareness.on("update", handleAwarenessUpdate);
        awarenessCleanup = () => {
          provider.awareness.off("update", handleAwarenessUpdate);
        };

        bindingRef.current = binding;
      } catch (e) {
        console.error("Yjs binding error:", e);
      }
    })();

    return () => {
      disposed = true;
      awarenessCleanup();
      if (bindingRef.current) {
        bindingRef.current.destroy();
        bindingRef.current = null;
      }
    };
  }, [activeFile?.filename, activeFile?.fileExtension, playgroundId, isMounted]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (inlineProviderDisposable) {
        inlineProviderDisposable.dispose();
        inlineProviderDisposable = null;
      }
      if (formatterDisposable) {
        formatterDisposable.dispose();
        formatterDisposable = null;
      }
      if (bindingRef.current) {
        bindingRef.current.destroy();
        bindingRef.current = null;
      }
      if (playgroundId) {
        destroyYDoc(playgroundId);
      }
    };
  }, [playgroundId]);

  const { editorTheme } = useAI();

  useEffect(() => {
    async function loadTheme() {
      if (!monacoRef.current) return;

      const sanitizeThemeId = (name: string) => name.replace(/[^a-zA-Z0-9-]/g, "-").toLowerCase();
      const safeThemeId = sanitizeThemeId(editorTheme);

      if (editorTheme === "vs-dark" || editorTheme === "vs" || editorTheme === "hc-black") {
        monacoRef.current.editor.setTheme(editorTheme);
        return;
      }

      try {
        const res = await fetch(`/themes/${editorTheme}.json`);
        if (!res.ok) throw new Error("Network response was not ok");
        const themeData = await res.json();

        monacoRef.current.editor.defineTheme(safeThemeId, themeData);
        monacoRef.current.editor.setTheme(safeThemeId);
      } catch (error) {
        console.error("Failed to load Monaco theme", error);
        monacoRef.current.editor.setTheme("vs-dark"); // fallback
      }
    }

    loadTheme();
  }, [editorTheme]);

  return (
    <div className="h-full relative">
      <Editor
        height={"100%"}
        defaultValue={content}
        onChange={(value) => onContentChange(value || "")}
        onMount={handleEditorDidMount}
        language={
          activeFile
            ? getEditorLanguage(activeFile.fileExtension || "")
            : "plaintext"
        }
        // @ts-ignore
        options={{
          ...defaultEditorOptions,
          inlineSuggest: { enabled: true },
        }}
      />
    </div>
  );
};

