interface PlaygroundSidebarProps {
    templateData: any;
    instance: any;
    writeFileSync: any;
    activeFile: any;
    handleFileSelect: any;
    wrappedHandleAddFile: any;
    wrappedHandleAddFolder: any;
    wrappedHandleDeleteFile: any;
    wrappedHandleDeleteFolder: any;
    wrappedHandleRenameFile: any;
