"use client";

import { create } from "zustand";

export type AIProvider = "gemini" | "groq" | "mistral";

export interface ChatMessage {
    id: string;
    role: "user" | "assistant" | "tool_activity";
    content: string;
    timestamp: number;
}

interface AIState {
    provider: AIProvider;
    isChatOpen: boolean;
    chatMessages: ChatMessage[];
    isGenerating: boolean;
    inlineSuggestionsEnabled: boolean;
    editorTheme: string;

    // User API keys (persisted to localStorage)
    userGeminiKey: string;
    userGroqKey: string;
    userMistralKey: string;

    // Actions
    setProvider: (provider: AIProvider) => void;
    toggleChat: () => void;
    openChat: () => void;
    closeChat: () => void;
    addMessage: (message: Omit<ChatMessage, "id" | "timestamp">) => void;
    clearChat: () => void;
    setIsGenerating: (val: boolean) => void;
    setUserApiKey: (provider: AIProvider, key: string) => void;
    getUserApiKey: (provider?: AIProvider) => string;
    toggleInlineSuggestions: () => void;
    setEditorTheme: (theme: string) => void;
}

function loadUserKeys() {
    if (typeof window === "undefined") return { gemini: "", groq: "", mistral: "" };
    try {
        return {
            gemini: localStorage.getItem("editron_gemini_key") || "",
            groq: localStorage.getItem("editron_groq_key") || "",
            mistral: localStorage.getItem("editron_mistral_key") || "",
        };
    } catch {
        return { gemini: "", groq: "", mistral: "" };
    }
}

export const useAI = create<AIState>((set, get) => {
    const keys = loadUserKeys();
    const inlineEnabled = typeof window !== "undefined"
        ? localStorage.getItem("editron_inline_suggestions") !== "false"
        : true;

    return {
        provider: "mistral",
        isChatOpen: false,
        chatMessages: [],
        isGenerating: false,
        inlineSuggestionsEnabled: inlineEnabled,
        editorTheme: typeof window !== "undefined" ? localStorage.getItem("editron_editor_theme") || "vs-dark" : "vs-dark",
        userGeminiKey: keys.gemini,
        userGroqKey: keys.groq,
        userMistralKey: keys.mistral,

        setProvider: (provider) => set({ provider }),
        toggleChat: () => set((s) => ({ isChatOpen: !s.isChatOpen })),
        openChat: () => set({ isChatOpen: true }),
        closeChat: () => set({ isChatOpen: false }),

        addMessage: (message) =>
            set((s) => ({
                chatMessages: [
                    ...s.chatMessages,
                    {
                        ...message,
                        id: `msg_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
                        timestamp: Date.now(),
                    },
                ],
            })),

        clearChat: () => set({ chatMessages: [] }),
        setIsGenerating: (val) => set({ isGenerating: val }),

        toggleInlineSuggestions: () => {
            const next = !get().inlineSuggestionsEnabled;
            try { localStorage.setItem("editron_inline_suggestions", String(next)); } catch { }
            set({ inlineSuggestionsEnabled: next });
        },

        setEditorTheme: (theme: string) => {
            try { localStorage.setItem("editron_editor_theme", theme); } catch { }
            set({ editorTheme: theme });
        },

        setUserApiKey: (provider, key) => {
            const storageKeys: Record<AIProvider, string> = {
                gemini: "editron_gemini_key",
                groq: "editron_groq_key",
                mistral: "editron_mistral_key",
            };
            try {
                localStorage.setItem(storageKeys[provider], key);
            } catch { }

            const stateKeys: Record<AIProvider, string> = {
                gemini: "userGeminiKey",
                groq: "userGroqKey",
                mistral: "userMistralKey",
            };
            set({ [stateKeys[provider]]: key } as any);
        },

        getUserApiKey: (provider) => {
            const p = provider || get().provider;
            if (p === "gemini") return get().userGeminiKey;
            if (p === "groq") return get().userGroqKey;
            return get().userMistralKey;
        },
    };
});

// --- Helpers ---
export function collectFilePaths(items: any[], prefix = ""): string[] {
    const paths: string[] = [];
    for (const item of items) {
        if ("folderName" in item) {
            const fp = prefix ? `${prefix}/${item.folderName}` : item.folderName;
            paths.push(fp + "/");
            paths.push(...collectFilePaths(item.items, fp));
        } else {
            const ext = item.fileExtension ? `.${item.fileExtension}` : "";
            paths.push(prefix ? `${prefix}/${item.filename}${ext}` : `${item.filename}${ext}`);
        }
    }
    return paths;
}

export function findFileByPath(items: any[], targetPath: string, prefix = ""): any | null {
    for (const item of items) {
        if ("folderName" in item) {
            const fp = prefix ? `${prefix}/${item.folderName}` : item.folderName;
            const found = findFileByPath(item.items, targetPath, fp);
            if (found) return found;
        } else {
            const ext = item.fileExtension ? `.${item.fileExtension}` : "";
            const filePath = prefix ? `${prefix}/${item.filename}${ext}` : `${item.filename}${ext}`;
            if (filePath === targetPath) return item;
        }
    }
    return null;
}

export function deleteFileByPath(items: any[], targetPath: string, prefix = ""): any[] {
    return items.filter((item) => {
        if ("folderName" in item) {
            const fp = prefix ? `${prefix}/${item.folderName}` : item.folderName;
            item.items = deleteFileByPath(item.items, targetPath, fp);
            return true;
        } else {
            const ext = item.fileExtension ? `.${item.fileExtension}` : "";
            const filePath = prefix ? `${prefix}/${item.filename}${ext}` : `${item.filename}${ext}`;
            return filePath !== targetPath;
        }
    });
}

export function addOrUpdateFile(items: any[], targetPath: string, newContent: string, prefix = ""): any[] {
    // 1. Try to find and update existing file
    let found = false;
    const updated = items.map((item) => {
        if ("folderName" in item) {
            const fp = prefix ? `${prefix}/${item.folderName}` : item.folderName;
            // Only recurse if the target path starts with this folder's path
            if (targetPath.startsWith(fp + "/")) {
                const newItems = addOrUpdateFile(item.items, targetPath, newContent, fp);
                // If the recursive call returned something different (or we know we found it inside),
                // we assume it handled it. But we need to know if it was *found*.
                // A simpler check: if the recursive call results in a change, use it.
                // Actually, let's just use the result.
                return { ...item, items: newItems };
            }
            return item;
        } else {
            const ext = item.fileExtension ? `.${item.fileExtension}` : "";
            const filePath = prefix ? `${prefix}/${item.filename}${ext}` : `${item.filename}${ext}`;
            if (filePath === targetPath) {
                found = true;
                return { ...item, content: newContent };
            }
            return item;
        }
    });

    // If we found and updated the file (or it was handled in recursion which we can't easily detect with just map),
    // we need a better strategy. passing 'found' back up is hard with just return value.

    // BETTER STRATEGY:
    // Check if file exists using findFileByPath.
    // If yes, use the map logic to update.
    // If no, we need to CREATE it.

    // Let's rewrite this function to be cleaner.
    // We can use a separate "create" path if "update" fails? 
    // No, recursive creation is best done in one go.

    // For now, let's stick to the existing update logic BUT use a helper to detect if it exists first.
    const existing = findFileByPath(items, targetPath, prefix);
    if (existing) {
        return items.map((item) => {
            if ("folderName" in item) {
                const fp = prefix ? `${prefix}/${item.folderName}` : item.folderName;
                if (targetPath.startsWith(fp + "/")) {
                    return { ...item, items: addOrUpdateFile(item.items, targetPath, newContent, fp) };
                }
                return item;
            } else {
                const ext = item.fileExtension ? `.${item.fileExtension}` : "";
                const filePath = prefix ? `${prefix}/${item.filename}${ext}` : `${item.filename}${ext}`;
                if (filePath === targetPath) return { ...item, content: newContent };
                return item;
            }
        });
    }

    // 2. If not found, we need to create it.
    // Split path to find where to insert.
    // e.g. "foo/bar/baz.txt" -> at root, look for "foo".
    const relativePath = prefix ? targetPath.slice(prefix.length + 1) : targetPath;
    const parts = relativePath.split("/");
    const nextPart = parts[0];

    // If this is the last part, it's the file to create
    if (parts.length === 1) {
        const fileName = nextPart;
        const lastDot = fileName.lastIndexOf(".");
        const name = lastDot > -1 ? fileName.slice(0, lastDot) : fileName;
        const ext = lastDot > -1 ? fileName.slice(lastDot + 1) : "";
        return [...items, { filename: name, fileExtension: ext, content: newContent }];
    }

    // Otherwise, we need to find or create the folder 'nextPart'
    const folderIndex = items.findIndex((item) => "folderName" in item && item.folderName === nextPart);

    if (folderIndex > -1) {
        // Folder exists, recurse into it
        const newItems = [...items];
        const folder = newItems[folderIndex];
        const fp = prefix ? `${prefix}/${folder.folderName}` : folder.folderName;
        newItems[folderIndex] = {
            ...folder,
            items: addOrUpdateFile(folder.items, targetPath, newContent, fp)
        };
        return newItems;
    } else {
        // Folder doesn't exist, create it and recurse
        const fp = prefix ? `${prefix}/${nextPart}` : nextPart;
        // Construct the new folder structure recursively
        // A shortcut: we can just call addOrUpdateFile on an empty array for the rest of path
        // but we need to pass the correct prefix.

        // Actually, we can just create the folder item with the rest of the path resolved.
        const newFolder = {
            folderName: nextPart,
            items: addOrUpdateFile([], targetPath, newContent, fp)
        };
        return [...items, newFolder];
    }
}

import { useState, useEffect, useCallback } from 'react';
import { toast } from 'sonner';
// import { getPlaygroundById, SaveUpdatedCode } from '@/features/playground/actions';
import type { TemplateFolder } from '../lib/path-to-json';
import { getPlaygroundById, SaveUpdatedCode } from '../actions';
import { title } from 'process';
// import { SaveUpdatedCode } from '../actions';

interface PlaygroundData {
  id: string;
  title?: string;
  [key: string]: any;
}

interface UsePlaygroundReturn {
  playgroundData: PlaygroundData | null;
  templateData: TemplateFolder | null;
  isLoading: boolean;
  error: string | null;
  loadPlayground: () => Promise<void>;
  saveTemplateData: (data: TemplateFolder) => Promise<void>;
}

export const usePlayground = (id: string): UsePlaygroundReturn => {
  const [playgroundData, setPlaygroundData] = useState<PlaygroundData | null>(null);
  const [templateData, setTemplateData] = useState<TemplateFolder | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const loadPlayground = useCallback(async () => {
    if (!id) return;

    try {
      setIsLoading(true);
      setError(null);

      const data = await getPlaygroundById(id);
      //   @ts-ignore
      setPlaygroundData(data);

      const rawContent = data?.templateFiles?.[0]?.content;
      if (rawContent) {
        // Content can be a JSON string or an already-parsed object (Prisma Json type)
        const parsedContent = typeof rawContent === "string"
          ? JSON.parse(rawContent)
          : rawContent;
        setTemplateData(parsedContent as TemplateFolder);
        toast.success("Playground loaded successfully");
        return;
      }

      // Load template from API if not in saved content
      const res = await fetch(`/api/template/${id}`);
      if (!res.ok) throw new Error(`Failed to load template: ${res.status}`);

      const templateRes = await res.json();
      if (templateRes.templateJson && Array.isArray(templateRes.templateJson)) {
        setTemplateData({
          folderName: "Root",
          items: templateRes.templateJson,
        });
      } else {
        setTemplateData(templateRes.templateJson || {
          folderName: "Root",
          items: [],
        });
      }

      toast.success("Template loaded successfully");
    } catch (error) {
      console.error("Error loading playground:", error);
      setError("Failed to load playground data");
      toast.error("Failed to load playground data");
    } finally {
      setIsLoading(false);
    }
  }, [id]);

  const saveTemplateData = useCallback(async (data: TemplateFolder) => {
    try {
      await SaveUpdatedCode(id, data);
      setTemplateData(data);
      toast.success("Changes saved successfully");
    } catch (error) {
      console.error("Error saving template data:", error);
      toast.error("Failed to save changes");
      throw error;
    }
  }, [id]);

  useEffect(() => {
    loadPlayground();
  }, [loadPlayground]);

  return {
    playgroundData,
    templateData,
    isLoading,
    error,
    loadPlayground,
    saveTemplateData,
  };
};

import * as fs from 'fs';
import * as path from 'path';

/**
 * Represents a file in the template structure
 */
export interface TemplateFile {
  filename: string;
  fileExtension: string;
  content: string;
}

/**
 * Represents a folder in the template structure which can contain files and other folders
 */
export interface TemplateFolder {
  folderName: string;
  items: (TemplateFile | TemplateFolder)[];
}

/**
 * Type representing either a file or folder in the template structure
 */
export type TemplateItem = TemplateFile | TemplateFolder;

/**
 * Options for scanning template directories
 */
interface ScanOptions {
  /**
   * Files to ignore (exact filenames with extensions)
   */
  ignoreFiles?: string[];
  
  /**
   * Folders to ignore (exact folder names)
   */
  ignoreFolders?: string[];
  
  /**
   * File patterns to ignore (regex patterns)
   */
  ignorePatterns?: RegExp[];
  
  /**
   * Maximum size of file to include content (in bytes)
   * Files larger than this will have a placeholder message instead of content
   */
  maxFileSize?: number;
}

/**
 * Scans a template directory and returns a structured JSON representation
 * 
 * @param templatePath - Path to the template directory
 * @param options - Scanning options to customize behavior
 * @returns Promise resolving to the template structure as JSON
 */
export async function scanTemplateDirectory(
  templatePath: string,
  options: ScanOptions = {}
): Promise<TemplateFolder> {
  // Set default options
  const defaultOptions: ScanOptions = {
    ignoreFiles: [
      '.DS_Store',
      'thumbs.db',
      '.gitignore',
      '.npmrc',
      '.yarnrc',
      '.env',
      '.env.local',
      '.env.development',
      '.env.production'
    ],
    ignoreFolders: [
      'node_modules',
      '.git',
      '.vscode',
      '.idea',
      'dist',
      'build',
      'coverage'
    ],
    ignorePatterns: [
      /^\..+\.swp$/,  // Vim swap files
      /^\.#/,         // Emacs backup files
      /~$/            // Backup files
    ],
    maxFileSize: 1024 * 1024 // 1MB
  };
  
  // Merge provided options with defaults
  const mergedOptions: ScanOptions = {
    ignoreFiles: [...(defaultOptions.ignoreFiles || []), ...(options.ignoreFiles || [])],
    ignoreFolders: [...(defaultOptions.ignoreFolders || []), ...(options.ignoreFolders || [])],
    ignorePatterns: [...(defaultOptions.ignorePatterns || []), ...(options.ignorePatterns || [])],
    maxFileSize: options.maxFileSize !== undefined ? options.maxFileSize : defaultOptions.maxFileSize
  };

  // Validate the input path
  if (!templatePath) {
    throw new Error('Template path is required');
  }

  // Check if the template path exists
  try {
    const stats = await fs.promises.stat(templatePath);
    if (!stats.isDirectory()) {
      throw new Error(`'${templatePath}' is not a directory`);
    }
  } catch (error) {
    if ((error as NodeJS.ErrnoException).code === 'ENOENT') {
      throw new Error(`Template directory '${templatePath}' does not exist`);
    }
    throw error;
  }

  // Get the folder name from the path
  const folderName = path.basename(templatePath);

  // Process the directory and return the result
  return processDirectory(folderName, templatePath, mergedOptions);
}

/**
 * Process a directory and its contents recursively
 * 
 * @param folderName - Name of the current folder
 * @param folderPath - Path to the current folder
 * @param options - Scanning options
 * @returns Promise resolving to a TemplateFolder object
 */
async function processDirectory(
  folderName: string, 
  folderPath: string, 
  options: ScanOptions
): Promise<TemplateFolder> {
  try {
    // Read directory contents
    const entries = await fs.promises.readdir(folderPath, { withFileTypes: true });
    const items: TemplateItem[] = [];

    // Process each entry in the directory
    for (const entry of entries) {
      const entryName = entry.name;
      const entryPath = path.join(folderPath, entryName);

      // Check if this entry should be skipped
      if (entry.isDirectory()) {
        // Skip ignored folders
        if (options.ignoreFolders?.includes(entryName)) {
          console.log(`Skipping ignored folder: ${entryPath}`);
          continue;
        }
        
        // If it's a directory, process it recursively
        const subFolder = await processDirectory(entryName, entryPath, options);
        items.push(subFolder);
      } else if (entry.isFile()) {
        // Skip ignored files
        if (options.ignoreFiles?.includes(entryName)) {
          console.log(`Skipping ignored file: ${entryPath}`);
          continue;
        }
        
        // Check against regex patterns
        const shouldSkip = options.ignorePatterns?.some(pattern => pattern.test(entryName));
        if (shouldSkip) {
          console.log(`Skipping file matching ignore pattern: ${entryPath}`);
          continue;
        }
        
        // If it's a file, get its details
        try {
          const stats = await fs.promises.stat(entryPath);
          const parsedPath = path.parse(entryName);
          let content: string;
          
          // Check file size before reading content
          if (options.maxFileSize && stats.size > options.maxFileSize) {
            content = `[File content not included: size (${stats.size} bytes) exceeds maximum allowed size (${options.maxFileSize} bytes)]`;
          } else {
            content = await fs.promises.readFile(entryPath, 'utf8');
          }
          
          items.push({
            filename: parsedPath.name,
            fileExtension: parsedPath.ext.replace(/^\./, ''), // Remove leading dot
            content
          });
        } catch (error) {
          console.error(`Error reading file ${entryPath}:`, error);
          // Still include the file but with an error message as content
          const parsedPath = path.parse(entryName);
          items.push({
            filename: parsedPath.name,
            fileExtension: parsedPath.ext.replace(/^\./, ''),
            content: `Error reading file: ${(error as Error).message}`
          });
        }
      }
      // Ignore other types of entries (symlinks, etc.)
    }

    // Return the folder with its items
    return {
      folderName,
      items
    };
  } catch (error) {
    throw new Error(`Error processing directory '${folderPath}': ${(error as Error).message}`);
  }
}

/**
 * Saves the template structure to a JSON file
 * 
 * @param templatePath - Path to the template directory
 * @param outputPath - Path where the JSON file should be saved
 * @param options - Scanning options
 * @returns Promise resolving when the file has been written
 */
export async function saveTemplateStructureToJson(
  templatePath: string, 
  outputPath: string,
  options?: ScanOptions
): Promise<void> {
  try {
    // Scan the template directory
    const templateStructure = await scanTemplateDirectory(templatePath, options);
    
    // Ensure the output directory exists
    const outputDir = path.dirname(outputPath);
    await fs.promises.mkdir(outputDir, { recursive: true });
    
    // Write the JSON file
    const data = await fs.promises.writeFile(
      outputPath, 
      JSON.stringify(templateStructure, null, 2),
      'utf8'
    );
    console.log(`Template structure saved to ${outputPath}`);


    
  } catch (error) {
    throw new Error(`Error saving template structure: ${(error as Error).message}`);
  }
}

export async function readTemplateStructureFromJson(filePath: string): Promise<TemplateFolder> {
  try {
    const data = await fs.promises.readFile(filePath, 'utf8');
    return JSON.parse(data) as TemplateFolder;
  } catch (error) {
    throw new Error(`Error reading template structure: ${(error as Error).message}`);
  }
}

