"use client";

import React, { useEffect, useRef, useState, useCallback, forwardRef, useImperativeHandle } from "react";
import { Terminal } from "xterm";
import { FitAddon } from "xterm-addon-fit";
import { WebLinksAddon } from "xterm-addon-web-links";
import { SearchAddon } from "xterm-addon-search";
import "xterm/css/xterm.css";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search, Copy, Trash2, Download } from "lucide-react";
import { cn } from "@/lib/utils";

interface TerminalProps {
  webcontainerUrl?: string;
  className?: string;
  theme?: "dark" | "light";
  webContainerInstance?: any;
}

// Define the methods that will be exposed through the ref
export interface TerminalRef {
  writeToTerminal: (data: string) => void;
  clearTerminal: () => void;
  focusTerminal: () => void;
}

const
  TerminalComponent = forwardRef<TerminalRef, TerminalProps>(({
    webcontainerUrl,
    className,
    theme = "dark",
    webContainerInstance
  }, ref) => {
    const terminalRef = useRef<HTMLDivElement>(null);
    const term = useRef<Terminal | null>(null);
    const fitAddon = useRef<FitAddon | null>(null);
    const searchAddon = useRef<SearchAddon | null>(null);
    const [isConnected, setIsConnected] = useState(false);
    const [searchTerm, setSearchTerm] = useState("");
    const [showSearch, setShowSearch] = useState(false);

    // Command line state
    const currentLine = useRef<string>("");
    const cursorPosition = useRef<number>(0);
    const commandHistory = useRef<string[]>([]);
    const historyIndex = useRef<number>(-1);
    const currentProcess = useRef<any>(null);
    const shellProcess = useRef<any>(null);

    const terminalThemes = {
      dark: {
        background: "#09090B",
        foreground: "#FAFAFA",
        cursor: "#FAFAFA",
        cursorAccent: "#09090B",
        selection: "#27272A",
        black: "#18181B",
        red: "#EF4444",
        green: "#22C55E",
        yellow: "#EAB308",
        blue: "#3B82F6",
        magenta: "#A855F7",
        cyan: "#06B6D4",
        white: "#F4F4F5",
        brightBlack: "#3F3F46",
        brightRed: "#F87171",
        brightGreen: "#4ADE80",
        brightYellow: "#FDE047",
        brightBlue: "#60A5FA",
        brightMagenta: "#C084FC",
        brightCyan: "#22D3EE",
        brightWhite: "#FFFFFF",
      },
      light: {
        background: "#FFFFFF",
        foreground: "#18181B",
        cursor: "#18181B",
        cursorAccent: "#FFFFFF",
        selection: "#E4E4E7",
        black: "#18181B",
        red: "#DC2626",
        green: "#16A34A",
        yellow: "#CA8A04",
        blue: "#2563EB",
        magenta: "#9333EA",
        cyan: "#0891B2",
        white: "#F4F4F5",
        brightBlack: "#71717A",
        brightRed: "#EF4444",
        brightGreen: "#22C55E",
        brightYellow: "#EAB308",
        brightBlue: "#3B82F6",
        brightMagenta: "#A855F7",
        brightCyan: "#06B6D4",
        brightWhite: "#FAFAFA",
      },
    };

    const writePrompt = useCallback(() => {
      if (term.current) {
        term.current.write("\r\n$ ");
        currentLine.current = "";
        cursorPosition.current = 0;
      }
    }, []);

    // Expose methods through ref
    useImperativeHandle(ref, () => ({
      writeToTerminal: (data: string) => {
        if (term.current) {
          term.current.write(data);
        }
      },
      clearTerminal: () => {
        clearTerminal();
      },
      focusTerminal: () => {
        if (term.current) {
          term.current.focus();
        }
      },
    }));

    const executeCommand = useCallback(async (command: string) => {
      if (!webContainerInstance || !term.current) return;

      // Add to history
      if (command.trim() && commandHistory.current[commandHistory.current.length - 1] !== command) {
        commandHistory.current.push(command);
      }
      historyIndex.current = -1;

      try {
        // Handle built-in commands
        if (command.trim() === "clear") {
          term.current.clear();
          writePrompt();
          return;
        }

        if (command.trim() === "history") {
          commandHistory.current.forEach((cmd, index) => {
            term.current!.writeln(`  ${index + 1}  ${cmd}`);
          });
          writePrompt();
          return;
        }

        if (command.trim() === "") {
          writePrompt();
          return;
        }

        // Parse command
        const parts = command.trim().split(' ');
        const cmd = parts[0];
        const args = parts.slice(1);

        // Execute in WebContainer
        term.current.writeln("");
        const process = await webContainerInstance.spawn(cmd, args, {
          terminal: {
            cols: term.current.cols,
            rows: term.current.rows,
          },
        });

        currentProcess.current = process;

        // Handle process output
        process.output.pipeTo(new WritableStream({
          write(data) {
            if (term.current) {
              term.current.write(data);
            }
          },
        }));

        // Wait for process to complete
        const exitCode = await process.exit;
        currentProcess.current = null;

        // Show new prompt
        writePrompt();

      } catch (error) {
        if (term.current) {
          term.current.writeln(`\r\nCommand not found: ${command}`);
          writePrompt();
        }
        currentProcess.current = null;
      }
    }, [webContainerInstance, writePrompt]);

    const handleTerminalInput = useCallback((data: string) => {
      if (!term.current) return;

      // Handle special characters
      switch (data) {
        case '\r': // Enter
          executeCommand(currentLine.current);
          break;

        case '\u007F': // Backspace
          if (cursorPosition.current > 0) {
            currentLine.current =
              currentLine.current.slice(0, cursorPosition.current - 1) +
              currentLine.current.slice(cursorPosition.current);
            cursorPosition.current--;

            // Update terminal display
            term.current.write('\b \b');
          }
          break;

        case '\u0003': // Ctrl+C
          if (currentProcess.current) {
            currentProcess.current.kill();
            currentProcess.current = null;
          }
          term.current.writeln("^C");
          writePrompt();
          break;

        case '\u001b[A': // Up arrow
          if (commandHistory.current.length > 0) {
            if (historyIndex.current === -1) {
              historyIndex.current = commandHistory.current.length - 1;
            } else if (historyIndex.current > 0) {
              historyIndex.current--;
            }

            // Clear current line and write history command
            const historyCommand = commandHistory.current[historyIndex.current];
            term.current.write('\r$ ' + ' '.repeat(currentLine.current.length) + '\r$ ');
            term.current.write(historyCommand);
            currentLine.current = historyCommand;
            cursorPosition.current = historyCommand.length;
          }
          break;

        case '\u001b[B': // Down arrow
          if (historyIndex.current !== -1) {
            if (historyIndex.current < commandHistory.current.length - 1) {
              historyIndex.current++;
              const historyCommand = commandHistory.current[historyIndex.current];
              term.current.write('\r$ ' + ' '.repeat(currentLine.current.length) + '\r$ ');
              term.current.write(historyCommand);
              currentLine.current = historyCommand;
              cursorPosition.current = historyCommand.length;
            } else {
              historyIndex.current = -1;
              term.current.write('\r$ ' + ' '.repeat(currentLine.current.length) + '\r$ ');
              currentLine.current = "";
              cursorPosition.current = 0;
            }
          }
          break;

        default:
          // Regular character input
          if (data >= ' ' || data === '\t') {
            currentLine.current =
              currentLine.current.slice(0, cursorPosition.current) +
              data +
              currentLine.current.slice(cursorPosition.current);
            cursorPosition.current++;
            term.current.write(data);
          }
          break;
      }
    }, [executeCommand, writePrompt]);

    const initializeTerminal = useCallback(() => {
      if (!terminalRef.current || term.current) return;

      const terminal = new Terminal({
        cursorBlink: true,
        fontFamily: '"Fira Code", "JetBrains Mono", "Consolas", monospace',
        fontSize: 14,
        lineHeight: 1.2,
        letterSpacing: 0,
        theme: terminalThemes[theme],
        allowTransparency: false,
        convertEol: true,
        scrollback: 1000,
        tabStopWidth: 4,
      });

      // Add addons
      const fitAddonInstance = new FitAddon();
      const webLinksAddon = new WebLinksAddon();
      const searchAddonInstance = new SearchAddon();

      terminal.loadAddon(fitAddonInstance);
      terminal.loadAddon(webLinksAddon);
      terminal.loadAddon(searchAddonInstance);

      terminal.open(terminalRef.current);

      fitAddon.current = fitAddonInstance;
      searchAddon.current = searchAddonInstance;
      term.current = terminal;

      // Handle terminal input
      terminal.onData(handleTerminalInput);

      // Initial fit
      setTimeout(() => {
        if (fitAddonInstance && term.current) {
          try {
            fitAddonInstance.fit();
          } catch (e) {
            console.warn("Failed to fit terminal:", e);
          }
        }
      }, 100);

      // Welcome message
      terminal.writeln("🚀 WebContainer Terminal");
      terminal.writeln("Type 'help' for available commands");
      writePrompt();

      return terminal;
    }, [theme, handleTerminalInput, writePrompt]);

    const connectToWebContainer = useCallback(async () => {
      if (!webContainerInstance || !term.current) return;

      try {
        setIsConnected(true);
        term.current.writeln("✅ Connected to WebContainer");
        term.current.writeln("Ready to execute commands");
        writePrompt();
      } catch (error) {
        setIsConnected(false);
        term.current.writeln("❌ Failed to connect to WebContainer");
        console.error("WebContainer connection error:", error);
      }
    }, [webContainerInstance, writePrompt]);

    const clearTerminal = useCallback(() => {
      if (term.current) {
        term.current.clear();
        term.current.writeln("🚀 WebContainer Terminal");
        writePrompt();
      }
    }, [writePrompt]);

    const copyTerminalContent = useCallback(async () => {
      if (term.current) {
        const content = term.current.getSelection();
        if (content) {
          try {
            await navigator.clipboard.writeText(content);
          } catch (error) {
            console.error("Failed to copy to clipboard:", error);
          }
        }
      }
    }, []);

    const downloadTerminalLog = useCallback(() => {
      if (term.current) {
        const buffer = term.current.buffer.active;
        let content = "";

        for (let i = 0; i < buffer.length; i++) {
          const line = buffer.getLine(i);
          if (line) {
            content += line.translateToString(true) + "\n";
          }
        }

        const blob = new Blob([content], { type: "text/plain" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `terminal-log-${new Date().toISOString().slice(0, 19)}.txt`;
        a.click();
        URL.revokeObjectURL(url);
      }
    }, []);

    const searchInTerminal = useCallback((term: string) => {
      if (searchAddon.current && term) {
        searchAddon.current.findNext(term);
      }
    }, []);

    useEffect(() => {
      initializeTerminal();

      // Handle resize
      const resizeObserver = new ResizeObserver(() => {
        if (fitAddon.current && term.current) {
          setTimeout(() => {
            if (fitAddon.current && term.current) {
              try {
                fitAddon.current.fit();
              } catch (e) {
                console.warn("Failed to fit terminal:", e);
              }
            }
          }, 100);
        }
      });

      if (terminalRef.current) {
        resizeObserver.observe(terminalRef.current);
      }

      return () => {
        resizeObserver.disconnect();
        if (currentProcess.current) {
          currentProcess.current.kill();
        }
        if (shellProcess.current) {
          shellProcess.current.kill();
        }
        if (term.current) {
          term.current.dispose();
          term.current = null;
        }
      };
    }, [initializeTerminal]);

    useEffect(() => {
      if (webContainerInstance && term.current && !isConnected) {
        connectToWebContainer();
      }
    }, [webContainerInstance, connectToWebContainer, isConnected]);

    return (
      <div className={cn("flex flex-col h-full bg-background border rounded-lg overflow-hidden", className)}>
        {/* Terminal Header */}
        <div className="flex items-center justify-between px-3 py-2 border-b bg-muted/50">
          <div className="flex items-center gap-2">
            <div className="flex gap-1">
              <div className="w-3 h-3 rounded-full bg-red-500"></div>
              <div className="w-3 h-3 rounded-full bg-yellow-500"></div>
              <div className="w-3 h-3 rounded-full bg-green-500"></div>
            </div>
            <span className="text-sm font-medium">WebContainer Terminal</span>
            {isConnected && (
              <div className="flex items-center gap-1">
                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                <span className="text-xs text-muted-foreground">Connected</span>
              </div>
            )}
          </div>

          <div className="flex items-center gap-1">
            {showSearch && (
              <div className="flex items-center gap-2">
                <Input
                  placeholder="Search..."
                  value={searchTerm}
                  onChange={(e) => {
                    setSearchTerm(e.target.value);
                    searchInTerminal(e.target.value);
                  }}
                  className="h-6 w-32 text-xs"
                />
              </div>
            )}

            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowSearch(!showSearch)}
              className="h-6 w-6 p-0"
            >
              <Search className="h-3 w-3" />
            </Button>

            <Button
              variant="ghost"
              size="sm"
              onClick={copyTerminalContent}
              className="h-6 w-6 p-0"
            >
              <Copy className="h-3 w-3" />
            </Button>

            <Button
              variant="ghost"
              size="sm"
              onClick={downloadTerminalLog}
              className="h-6 w-6 p-0"
            >
              <Download className="h-3 w-3" />
            </Button>

            <Button
              variant="ghost"
              size="sm"
              onClick={clearTerminal}
              className="h-6 w-6 p-0"
            >
              <Trash2 className="h-3 w-3" />
            </Button>
          </div>
        </div>

        {/* Terminal Content */}
        <div className="flex-1 relative">
          <div
            ref={terminalRef}
            className="absolute inset-0 p-2"
            style={{
              background: terminalThemes[theme].background,
            }}
          />
        </div>
      </div>
    );
  });

TerminalComponent.displayName = "TerminalComponent";

export default TerminalComponent;

"use client";
import React, { useEffect, useState, useRef } from "react";
import dynamic from "next/dynamic";

import { transformToWebContainerFormat } from "../hooks/transformer";
import { CheckCircle, Loader2, XCircle, ExternalLink, RefreshCw, Monitor, Tablet, Smartphone, Globe } from "lucide-react";
import { Progress } from "@/components/ui/progress";
import { Button } from "@/components/ui/button";
// import { Input } from "@/components/ui/input";

const TerminalComponent = dynamic(() => import("./terminal"), { ssr: false });

import { WebContainer } from "@webcontainer/api";
import { TemplateFolder } from "@/modules/playground/lib/path-to-json";

interface WebContainerPreviewProps {
  templateData: TemplateFolder;
  serverUrl: string;
  isLoading: boolean;
  error: string | null;
  instance: WebContainer | null;
  writeFileSync: (path: string, content: string) => Promise<void>;
  forceResetup?: boolean; // Optional prop to force re-setup
}
const WebContainerPreview = ({
  templateData,
  error,
  instance,
  isLoading,
  serverUrl,
  writeFileSync,
  forceResetup = false,
}: WebContainerPreviewProps) => {
  const [previewUrl, setPreviewUrl] = useState<string>("");
  const [refreshKey, setRefreshKey] = useState(0);
  const [viewport, setViewport] = useState<"desktop" | "tablet" | "mobile">("desktop");
  const [loadingState, setLoadingState] = useState({
    transforming: false,
    mounting: false,
    installing: false,
    starting: false,
    ready: false,
  });
  const [currentStep, setCurrentStep] = useState(0);
  const totalSteps = 4;
  const [setupError, setSetupError] = useState<string | null>(null);
  const [isSetupComplete, setIsSetupComplete] = useState(false);
  const [_isSetupInProgress, setIsSetupInProgress] = useState(false);
  const [installProgress, setInstallProgress] = useState({
    totalDeps: 0,
    installedPackages: 0,
    progressPercent: 0,
    statusText: "",
  });
  const terminalRef = useRef<any>(null);
  const setupInProgressRef = useRef(false);

  // Helper to count dependencies from package.json content
  const countDependencies = (pkgContent: string): number => {
    try {
      const pkg = JSON.parse(pkgContent);
      const deps = Object.keys(pkg.dependencies || {}).length;
      const devDeps = Object.keys(pkg.devDependencies || {}).length;
      return deps + devDeps;
    } catch {
      return 0;
    }
  };

  const createInstallOutputStream = (totalDeps : number) => {
    let estimatedProgress = 0;
    let lastUpdateTime = Date.now();
    
    return new WritableStream({
      write(data: string) {
        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(data);
        } else {
          console.log("[WebContainer Install] ", data.trim());
        }
        
        const now = Date.now();
        // Throttle state updates to at most once every 100ms
        const shouldUpdate = now - lastUpdateTime > 100;
        
        // Parse npm output for progress signals
        const addedMatch = data.match(/added (\d+) packages?/i);
        if (addedMatch) {
          const added = parseInt(addedMatch[1], 10);
          setInstallProgress((prev) => ({
            ...prev,
            installedPackages: added,
            progressPercent: 100,
            statusText: `Installed ${added} packages`,
          }));
          lastUpdateTime = now;
          return;
        }
        
        if (!shouldUpdate) return;
        
        // Detect resolution / reify / etc. phases
        if (data.includes("reify:") || data.includes("idealTree")) {
          estimatedProgress = Math.min(estimatedProgress + 2, 85);
          setInstallProgress((prev) => ({
            ...prev,
            progressPercent: estimatedProgress,
            statusText: "Resolving dependency tree...",
          }));
          lastUpdateTime = now;
        } else if (data.includes("http fetch") || data.includes("GET ")) {
          estimatedProgress = Math.min(estimatedProgress + 1, 70);
          setInstallProgress((prev) => ({
            ...prev,
            progressPercent: estimatedProgress,
            statusText: "Fetching packages...",
          }));
          lastUpdateTime = now;
        } else if (data.includes("WARN") || data.includes("warn")) {
          // Don't update progress on warnings
        } else if (data.trim().length > 0 && estimatedProgress < 90) {
          estimatedProgress = Math.min(estimatedProgress + 0.5, 90);
          setInstallProgress((prev) => ({
            ...prev,
            progressPercent: Math.round(estimatedProgress),
          }));
          lastUpdateTime = now;
        }
      },
    });
  };

  // Helper to detect package manager
  const detectPackageManager = async (instance: WebContainer): Promise<"npm" | "yarn" | "pnpm"> => {
    try {
      if (await instance.fs.readFile("pnpm-lock.yaml", "utf8").catch(() => null)) return "pnpm";
      if (await instance.fs.readFile("yarn.lock", "utf8").catch(() => null)) return "yarn";
      return "npm"; // Default
    } catch {
      return "npm";
    }
  };

  // Helper to determine the best start script and command
  const resolveStartCommand = async (instance: WebContainer, pkgManager: string, packageJsonString: string) => {
    try {
      const pkg = JSON.parse(packageJsonString);
      const scripts = pkg.scripts || {};

      // Check for monorepo configuration
      let isMonorepo = false;
      let workspaces: string[] = [];

      if (pkg.workspaces) {
        isMonorepo = true;
        workspaces = Array.isArray(pkg.workspaces) ? pkg.workspaces : (pkg.workspaces.packages || []);
      } else {
        const pnpmWorkspace = await instance.fs.readFile("pnpm-workspace.yaml", "utf8").catch(() => null);
        if (pnpmWorkspace) {
          isMonorepo = true;
          // Simple regex to extract packages from yaml
          const matches = [...pnpmWorkspace.matchAll(/-\s+['"]?([^'"\n]+)['"]?/g)];
          workspaces = matches.map(m => m[1]);
        }
      }

      if (isMonorepo && workspaces.length > 0) {
        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(
            `\x1b[36mℹ Detected monorepo structure with package manager: ${pkgManager}\x1b[0m\r\n`
          );
        }

        // Find the most likely frontend workspace (client, web, app, frontend)
        // const frontendKeywords = ["client", "web", "app", "ui", "frontend", "docs"];
        let bestWorkspaceDir = "";
        let bestScript = "";
        let bestWorkspaceName = "";

        // Since workspaces often have globs (e.g., "apps/*", "packages/*"), we check common directories
        const dirsToCheck = ["client", "web", "app", "frontend", "apps/web", "apps/client", "packages/web"];

        for (const dir of dirsToCheck) {
          try {
            const childPkgContent = await instance.fs.readFile(`${dir}/package.json`, "utf8");
            const childPkg = JSON.parse(childPkgContent);
            const childScripts = childPkg.scripts || {};

            if (childScripts.dev || childScripts.start || childScripts.serve) {
              bestWorkspaceDir = dir;
              bestWorkspaceName = childPkg.name || dir;
              bestScript = childScripts.dev ? "dev" : (childScripts.start ? "start" : "serve");
              break;
            }
          } catch  { }
        }

        if (bestWorkspaceDir && bestScript) {
          if (terminalRef.current?.writeToTerminal) {
            terminalRef.current.writeToTerminal(
              `\x1b[36mℹ Found frontend workspace: ${bestWorkspaceDir} (script: ${bestScript})\x1b[0m\r\n`
            );
          }

          if (pkgManager === "pnpm" && bestWorkspaceName) {
            return { cmd: "pnpm", args: ["--filter", bestWorkspaceName, "run", bestScript] };
          } else if (pkgManager === "yarn") {
            return { cmd: "yarn", args: ["workspace", bestWorkspaceName, "run", bestScript] };
          } else {
            return { cmd: "npm", args: ["run", bestScript, "--workspace=" + bestWorkspaceName] };
          }
        }
      }

      // Standard single-package resolution: Prefer dev over start for frontend tools
      if (scripts.dev) return { cmd: pkgManager, args: ["run", "dev"] };
      if (scripts.start) return { cmd: pkgManager, args: ["run", "start"] };
      if (scripts.serve) return { cmd: pkgManager, args: ["run", "serve"] };

      return { cmd: pkgManager, args: ["run", "start"] }; // Fallback
    } catch  {
      return { cmd: pkgManager, args: ["run", "start"] };
    }
  };

  // Reset setup state when forceResetup changes
  useEffect(() => {
    if (forceResetup) {
      setIsSetupComplete(false);
      setIsSetupInProgress(false);
      setupInProgressRef.current = false;
      setPreviewUrl("");
      setCurrentStep(0);
      setLoadingState({
        transforming: false,
        mounting: false,
        installing: false,
        starting: false,
        ready: false,
      });
    }
  }, [forceResetup]);

  useEffect(() => {
    async function setupContainer() {
      if (!instance || isSetupComplete || setupInProgressRef.current) return;

      try {
        setupInProgressRef.current = true;
        setIsSetupInProgress(true);
        setSetupError(null);

        try {
          const packageJsonExists = await instance.fs.readFile(
            "package.json",
            "utf8"
          );

          if (packageJsonExists) {
            // Files are already mounted, restart the server
            if (terminalRef.current?.writeToTerminal) {
              terminalRef.current.writeToTerminal(
                "🔄 Reconnecting to existing WebContainer session...\r\n"
              );
            }

            instance.on("server-ready", (port: number, url: string) => {
              if (terminalRef.current?.writeToTerminal) {
                terminalRef.current.writeToTerminal(
                  `🌐 Server ready at ${url} (port ${port})\r\n`
                );
              }

              const isCommonFrontendPort = [3000, 5173, 8080, 4200, 8000].includes(port);
              setPreviewUrl((prevUrl) => {
                if (prevUrl && !isCommonFrontendPort) return prevUrl;
                return url;
              });

              setLoadingState((prev) => ({
                ...prev,
                starting: false,
                ready: true,
              }));
              setIsSetupComplete(true);
              setIsSetupInProgress(false);
              setupInProgressRef.current = false;
            });

            setCurrentStep(3);
            setLoadingState((prev) => ({ ...prev, installing: true }));

            // Detect Package Manager
            const pkgManager = await detectPackageManager(instance);

            // Reinstall dependencies first (ensures local CLIs like ng, vite are available)
            // Count deps for progress bar
            let reconnectTotalDeps = 0;
            let pkgContent = "";
            try {
              pkgContent = await instance.fs.readFile("package.json", "utf8");
              reconnectTotalDeps = countDependencies(pkgContent);
            } catch { }
            setInstallProgress({ totalDeps: reconnectTotalDeps, installedPackages: 0, progressPercent: 0, statusText: "Starting install..." });

            if (terminalRef.current?.writeToTerminal) {
              terminalRef.current.writeToTerminal(
                `📦 Reinstalling dependencies using \x1b[33m${pkgManager}\x1b[0m (${reconnectTotalDeps} packages)...\r\n`
              );
            }

            const installArgs = pkgManager === "npm" ? ["install", "--no-audit", "--no-fund", "--legacy-peer-deps"] : ["install"];
            const reinstallProcess = await instance.spawn(pkgManager, installArgs);
            reinstallProcess.output.pipeTo(createInstallOutputStream(reconnectTotalDeps));
            const reinstallExitCode = await reinstallProcess.exit;
            if (reinstallExitCode !== 0) {
              if (terminalRef.current?.writeToTerminal) {
                terminalRef.current.writeToTerminal(
                  `⚠️ ${pkgManager} install exited with code ${reinstallExitCode}, attempting to start anyway...\r\n`
                );
              }
            } else {
              if (terminalRef.current?.writeToTerminal) {
                terminalRef.current.writeToTerminal(
                  "✅ Dependencies ready\r\n"
                );
              }
            }

            setLoadingState((prev) => ({ ...prev, installing: false, starting: true }));
            setCurrentStep(4);

            // Now restart the server
            const startCommand = await resolveStartCommand(instance, pkgManager, pkgContent);

            if (terminalRef.current?.writeToTerminal) {
              terminalRef.current.writeToTerminal(
                `🚀 Restarting development server via \x1b[32m${startCommand.cmd} ${startCommand.args.join(" ")}\x1b[0m...\r\n`
              );
            }
            const startProcess = await instance.spawn(startCommand.cmd, startCommand.args);
            startProcess.output.pipeTo(
              new WritableStream({
                write(data) {
                  if (terminalRef.current?.writeToTerminal) {
                    terminalRef.current.writeToTerminal(data);
                  }
                },
              })
            );
            return;
          }
        } catch  { }

        // Step-1 transform data
        setLoadingState((prev) => ({ ...prev, transforming: true }));
        setCurrentStep(1);
        // Write to terminal
        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(
            "🔄 Transforming template data...\r\n"
          );
        }

        // @ts-ignore
        const files = transformToWebContainerFormat(templateData);
        setLoadingState((prev) => ({
          ...prev,
          transforming: false,
          mounting: true,
        }));
        setCurrentStep(2);

        //  Step-2 Mount Files

        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(
            "📁 Mounting files to WebContainer...\r\n"
          );
        }
        await instance.mount(files);

        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(
            "✅ Files mounted successfully\r\n"
          );
        }

        // Check if package.json exists, if not create a default one for static serving
        try {
          const packageJsonContent = await instance.fs.readFile("package.json", "utf8").catch(() => null);

          if (!packageJsonContent) {
            if (terminalRef.current?.writeToTerminal) {
              terminalRef.current.writeToTerminal(
                "⚠️ No package.json found. Creating default configuration for static site...\r\n"
              );
            }
            await instance.fs.writeFile("package.json", JSON.stringify({
              name: "static-project",
              version: "1.0.0",
              scripts: {
                start: "npx servor --reload"
              },
              dependencies: {
                "servor": "^4.0.2"
              }
            }, null, 2));
          } else {
            // Check for missing start script and try to auto-fix
            try {
              const pkg = JSON.parse(packageJsonContent);
              if (!pkg.scripts || !pkg.scripts.start) {
                const commonEntries = ["index.js", "server.js", "app.js", "main.js", "src/index.js", "src/server.js", "src/app.js", "src/main.js"];
                let entryFile = null;

                for (const entry of commonEntries) {
                  try {
                    const exists = await instance.fs.readFile(entry).catch(() => null);
                    if (exists) {
                      entryFile = entry;
                      break;
                    }
                  } catch  { }
                }

                if (entryFile) {
                  if (terminalRef.current?.writeToTerminal) {
                    terminalRef.current.writeToTerminal(
                      `⚠️ No start script found. Auto-detected entry point: ${entryFile}. Injecting start script...\r\n`
                    );
                  }

                  pkg.scripts = pkg.scripts || {};
                  pkg.scripts.start = `node ${entryFile}`;

                  await instance.fs.writeFile("package.json", JSON.stringify(pkg, null, 2));
                } else {
                  // Check for client/server monorepo structure
                  const hasClient = await instance.fs.readFile("client/package.json", "utf8").catch(() => null);
                  const hasServer = await instance.fs.readFile("server/package.json", "utf8").catch(() => null);

                  if (hasClient || hasServer) {
                    const workspaces = [];
                    if (hasClient) workspaces.push("client");
                    if (hasServer) workspaces.push("server");

                    pkg.workspaces = workspaces;
                    pkg.scripts = pkg.scripts || {};

                    // Construct start script
                    // Helper to find valid script
                    const getScript = (pkgJson: string | null) => {
                      if (!pkgJson) return null;
                      try {
                        const parsed = JSON.parse(pkgJson);
                        return parsed.scripts?.dev ? "dev" : parsed.scripts?.start ? "start" : null;
                      } catch { return null; }
                    };

                    const clientScript = getScript(hasClient);
                    const serverScript = getScript(hasServer);

                    // Construct start script
                    if (hasClient && hasServer && clientScript && serverScript) {
                      // Attempt to start client last to capture its port, or use a tool like concurrently if available. 
                      // For now, valid method is:
                      pkg.scripts.start = `npm run ${serverScript} --prefix server & npm run ${clientScript} --prefix client`;
                    } else if (hasClient && clientScript) {
                      pkg.scripts.start = `npm run ${clientScript} --prefix client`;
                    } else if (hasServer && serverScript) {
                      pkg.scripts.start = `npm run ${serverScript} --prefix server`;
                    } else {
                      // Fallback
                      pkg.scripts.start = "echo 'No runnable scripts found'";
                    }

                    if (terminalRef.current?.writeToTerminal) {
                      terminalRef.current.writeToTerminal(
                        `⚠️ Detected monorepo structure (${workspaces.join(", ")}). Configuring workspaces and start script...\r\n`
                      );
                    }

                    // Ensure name and version exist for valid workspace root
                    if (!pkg.name) pkg.name = "monorepo-root";
                    if (!pkg.version) pkg.version = "1.0.0";

                    await instance.fs.writeFile("package.json", JSON.stringify(pkg, null, 2));
                  }
                }
              }
            } catch (e) {
              console.error("Error parsing/patching package.json:", e);
            }
          }
        } catch (error) {
          console.error("Error checking/creating package.json:", error);
        }

        setLoadingState((prev) => ({
          ...prev,
          mounting: false,
          installing: true,
        }));
        setCurrentStep(3);

        // Step-3 Install dependencies
        const pkgManager = await detectPackageManager(instance);

        // Count total dependencies for progress bar
        let totalDeps = 0;
        let pckgContent = "";
        try {
          pckgContent = await instance.fs.readFile("package.json", "utf8");
          totalDeps = countDependencies(pckgContent);
        } catch { }
        setInstallProgress({ totalDeps, installedPackages: 0, progressPercent: 0, statusText: "Starting install..." });

        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(
            `📦 Installing dependencies using \x1b[33m${pkgManager}\x1b[0m (${totalDeps} packages)...\r\n`
          );
        }

        // Prefer npm ci (reads lockfile, skips registry metadata = no JSON truncation in WebContainer)
        // Fall back to npm install if no lockfile is present
        let freshInstallArgs: string[];
        if (pkgManager === "npm") {
          const hasLockfile = await instance.fs.readFile("package-lock.json", "utf8").catch(() => null);
          if (hasLockfile) {
            freshInstallArgs = ["ci", "--no-audit", "--no-fund"];
            if (terminalRef.current?.writeToTerminal) {
              terminalRef.current.writeToTerminal("🔒 Lockfile found — using \x1b[32mnpm ci\x1b[0m for faster, reliable install...\r\n");
            }
          } else {
            freshInstallArgs = ["install", "--no-audit", "--no-fund", "--legacy-peer-deps"];
          }
        } else {
          freshInstallArgs = ["install"];
        }
        const installProcess = await instance.spawn(pkgManager, freshInstallArgs);

        installProcess.output.pipeTo(createInstallOutputStream(totalDeps));

        const installExitCode = await installProcess.exit;

        if (installExitCode !== 0) {
          if (terminalRef.current?.writeToTerminal) {
            terminalRef.current.writeToTerminal(
              `⚠️ Dependencies install exited with code ${installExitCode}, attempting to start anyway...\r\n`
            );
          }
          console.warn(`npm install exited with code ${installExitCode}`);
        } else {
          if (terminalRef.current?.writeToTerminal) {
            terminalRef.current.writeToTerminal(
              "✅ Dependencies installed successfully\r\n"
            );
          }
        }

        setLoadingState((prev) => ({
          ...prev,
          installing: false,
          starting: true,
        }));
        setCurrentStep(4);

        // STEP-4 Start The Server

        const startCommand = await resolveStartCommand(instance, pkgManager, pckgContent);

        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(
            `🚀 Starting development server via \x1b[32m${startCommand.cmd} ${startCommand.args.join(" ")}\x1b[0m...\r\n`
          );
        }

        const startProcess = await instance.spawn(startCommand.cmd, startCommand.args);

        instance.on("server-ready", (port: number, url: string) => {
          // todo: Terminal logic
          if (terminalRef.current?.writeToTerminal) {
            terminalRef.current.writeToTerminal(
              `🌐 Server ready at ${url} (port ${port})\r\n`
            );
          }

          // Heuristic: Prefer port 5173 (Vite) or 3000 (Create React App / Next.js) over others (often backend)
          // valid ports for frontend usually: 3000, 3001, 3002, 5173, 5174, 8080, 4200 (Angular), 8000 (Gatsby)
          const isCommonFrontendPort = [3000, 5173, 8080, 4200, 8000].includes(port);

          setPreviewUrl((prevUrl) => {
            // If we already have a URL and the new one isn't a "common frontend port", ignore it to avoid backend overriding frontend
            if (prevUrl && !isCommonFrontendPort) return prevUrl;
            return url;
          });

          setLoadingState((prev) => ({
            ...prev,
            starting: false,
            ready: true,
          }));
          setIsSetupComplete(true);
          setIsSetupInProgress(false);
          setupInProgressRef.current = false;
        });

        // Handle start process output - stream to terminal
        startProcess.output.pipeTo(
          new WritableStream({
            write(data) {
              if (terminalRef.current?.writeToTerminal) {
                terminalRef.current.writeToTerminal(data);
              }
            },
          })
        );
      } catch (err) {
        console.error("Error setting up container:", err);
        const errorMessage = err instanceof Error ? err.message : String(err);
        if (terminalRef.current?.writeToTerminal) {
          terminalRef.current.writeToTerminal(`❌ Error: ${errorMessage}\r\n`);
        }
        setSetupError(errorMessage);
        setIsSetupInProgress(false);
        setupInProgressRef.current = false;
        setLoadingState({
          transforming: false,
          mounting: false,
          installing: false,
          starting: false,
          ready: false,
        });
      }
    }

    setupContainer();
    // Only re-run when instance or templateData changes, NOT on isSetupInProgress changes
  }, [instance, templateData, isSetupComplete]);

  useEffect(() => {
    return () => { };
  }, []);

  if (isLoading) {
    return (
      <div className="h-full flex items-center justify-center">
        <div className="text-center space-y-4 max-w-md p-6 rounded-lg bg-gray-50 dark:bg-gray-900">
          <Loader2 className="h-10 w-10 animate-spin text-primary mx-auto" />
          <h3 className="text-lg font-medium">Initializing WebContainer</h3>
          <p className="text-sm text-gray-500 dark:text-gray-400">
